window.TRENDY_WORDS = [{"id":"1970-1","word":"청타맥","era":"1970년대","meaning":"청바지, 통기타, 생맥주의 앞 글자를 딴 말로 1970년대 청년 세대의 자유와 낭만 문화를 상징하는 대표어","example":"이번 주말에는 친구들과 신촌에서 청바지 입고 만나 청타맥을 한잔 기울이기로 했어.","tags":["청년문화","낭만","캠퍼스"],"themeColor":"bg-neon-blue"},{"id":"1970-2","word":"고고장","era":"1970년대","meaning":"사이키델릭 조명 아래에서 고고 춤을 출 수 있었던 당시 대학생들과 청년들의 유일한 댄스 홀이자 사교의 공간","example":"을지로에 새로 생긴 고고장에 한번 놀러 가 볼래?","tags":["댄스","놀이문화","사교"],"themeColor":"bg-neon-pink"},{"id":"1970-3","word":"장발단속","era":"1970년대","meaning":"1970년대 당시 정부의 사회 정화 정책으로 순경들이 자와 가위를 들고 길거리의 장발 청년들을 직접 단속하여 가위질했던 일화","example":"저기 길 건너에 순경 떴어! 장발단속 걸리기 전에 빨리 도망치자!","tags":["사회상","단속","역사"],"themeColor":"bg-neon-orange"},{"id":"1970-4","word":"바보들의 행진","era":"1970년대","meaning":"1970년대 당시 억압된 분위기 속에서 갈 길을 잃은 청춘들의 소심한 반항과 방황을 그린 영화 및 대중적 명대사","example":"요즘 대학 생활이 흘러가는 모습을 보니 다들 바보들의 행진 같구나.","tags":["영화","방황","청춘"],"themeColor":"bg-neon-green"},{"id":"1970-5","word":"학사주점","era":"1970년대","meaning":"1970년대 대학가 주변에 생겨나기 시작하여 대학생들이 값싼 양은 주전자에 막걸리를 가득 채워 마시며 정치와 철학을 토론하던 선술집","example":"수업 끝나면 막걸리가 맛있는 대학로 학사주점으로 모이기로 했어.","tags":["대학가","막걸리","토론"],"themeColor":"bg-neon-blue"},{"id":"1970-6","word":"명랑만화","era":"1970년대","meaning":"1970년대 전성기를 누린 밝고 유쾌하며 해학적인 대중 만화 장르. 지나치게 낙천적이거나 엉뚱한 사람을 놀릴 때 빗대어 부르기도 함","example":"너 행동하는 것 보니까 정말 명랑만화 주인공이 따로 없네.","tags":["만화","대중문화","비유"],"themeColor":"bg-neon-pink"},{"id":"1970-7","word":"돌도사","era":"1970년대","meaning":"시험 문제의 정답이나 타인의 속마음을 기막히게 잘 맞추거나 예측하는 촉이 뛰어난 사람을 친근하게 일컫던 유행어","example":"선생님이 낼 시험 문제를 족족 알아맞히다니 너 완전 돌도사로구나!","tags":["유행어","예측","재치"],"themeColor":"bg-neon-orange"},{"id":"1970-8","word":"얄개","era":"1970년대","meaning":"야속하고 얄미우면서도 엉뚱하고 귀여운 구석이 있는 개구쟁이 청소년을 친근하게 부르던 말","example":"우리 집 둘째 녀석은 어찌나 장난이 심한지 완전 골치 아픈 얄개야.","tags":["개구쟁이","학생","성격"],"themeColor":"bg-neon-green"},{"id":"1970-9","word":"디스코","era":"1970년대","meaning":"1970년대 후반 전 세계를 강타한 경쾌하고 강렬한 비트의 댄스 음악이자 청년들의 댄스 문화를 상징하는 키워드","example":"새로 산 나팔바지를 입고 주말에 친구들과 디스코 파티에 가기로 했어.","tags":["댄스","음악","유행"],"themeColor":"bg-neon-blue"},{"id":"1970-10","word":"미니스커트 단속","era":"1970년대","meaning":"경찰들이 길거리에서 자를 가지고 무릎 위 20cm 이상 치마를 단속하여 즉결심판에 넘기던 70년대의 웃지 못할 풍경","example":"단속반 눈을 피해 미니스커트를 가방에 숨겨 다니는 여학생들이 많았대.","tags":["역사","단속","패션"],"themeColor":"bg-neon-pink"},{"id":"1970-11","word":"통기타","era":"1970년대","meaning":"70년대 청춘들의 서정적이고 낭만적인 감성을 대변하며 대중 가요의 유행을 이끈 대표 악기이자 문화 코드","example":"잔디밭에 둘러앉아 통기타 연주를 들으며 다 같이 포크송을 따라 불렀지.","tags":["음악","낭만","대학생"],"themeColor":"bg-neon-orange"},{"id":"1970-12","word":"짱","era":"1970년대","meaning":"70년대 후반 서울의 고등학생들 사이에서 힘이 가장 세거나 우두머리인 학생을 지칭하기 시작하며 널리 퍼진 속어","example":"철수가 골목대장 노릇을 하더니 기어코 동네 짱이 되었구나.","tags":["최고","우두머리","학생"],"themeColor":"bg-neon-green"},{"id":"1970-13","word":"범생","era":"1970년대","meaning":"공부만 열심히 하고 모범적인 생활 방식을 완고하게 따르는 학생을 일컫는 말의 원형이자 초창기 은어","example":"영희는 방과 후에도 도서관에만 가니 틀림없는 범생이야.","tags":["학생","모범생","공부"],"themeColor":"bg-neon-blue"},{"id":"1970-14","word":"음악다방","era":"1970년대","meaning":"인기 DJ가 부스 안에서 신청곡과 사연을 소개하며 LP판 음악을 들려주던 청년들의 약속 장소이자 문화 아지트","example":"음악다방에서 설탕 세 스푼 넣은 커피를 마시며 좋아하는 팝송을 청취했어.","tags":["DJ","데이트","음악"],"themeColor":"bg-neon-pink"},{"id":"1970-15","word":"생맥주","era":"1970년대","meaning":"포크 음악과 함께 70년대 젊은이들의 갈증을 달래고 답답한 사회상에서 벗어나 해방감을 선사하던 상징적 주류","example":"하루의 고된 노동을 마친 후 차가운 생맥주 한 잔을 마시는 낙으로 살아.","tags":["술","청년문화","힐링"],"themeColor":"bg-neon-orange"},{"id":"1970-16","word":"빵집미팅","era":"1970년대","meaning":"70년대 청소년들이 단체로 동네 제과점이나 단팥빵 가게에 모여 수줍게 대화를 나누며 커플을 맺던 설레는 사교 문화","example":"이번 토요일 방과 후에 유명 빵집에서 제과점 미팅이 주선되었단다.","tags":["연애","빵집","미팅"],"themeColor":"bg-neon-green"},{"id":"1970-17","word":"밤차","era":"1970년대","meaning":"동명의 인기가요 가사에서 따온 유행어로, 어디론가 멀리 훌쩍 떠나는 기차 여행과 낭만적인 청춘의 해방을 비유적으로 이르는 말","example":"복잡한 서울을 벗어나 주말 밤차를 타고 정동진 바다로 향하고 싶어.","tags":["여행","가요","해방"],"themeColor":"bg-neon-blue"},{"id":"1970-18","word":"나팔바지","era":"1970년대","meaning":"허벅지 부위는 타이트하지만 무릎 아래부터 나팔꽃 모양처럼 통이 극적으로 넓어지던 70년대 최고의 하의 패션 아이템","example":"제일 아끼는 데님 나팔바지에 굽 높은 신발을 신으니 정말 신이 나는군.","tags":["패션","청바지","유행"],"themeColor":"bg-neon-pink"},{"id":"1970-19","word":"판타롱바지","era":"1970년대","meaning":"나팔바지와 혼용되어 불리던 외래어 패션 용어로, 당시 한껏 멋을 낸 세련된 남녀들의 드레스 코드이자 필수 복장","example":"화려한 무늬의 셔츠에 판타롱바지를 맞춰 입고 명동 거리를 활보했어.","tags":["의상","용어","스타일"],"themeColor":"bg-neon-orange"},{"id":"1970-20","word":"통금","era":"1970년대","meaning":"치안과 사회 통제를 위해 밤 12시부터 새벽 4시까지 민간인의 거리 통행을 금지하던 제도이자 수많은 청춘들이 추억을 쌓던 원인","example":"통금 시간이 닥치면 골목마다 순경의 사이렌 소리가 요란하게 울려 퍼졌지.","tags":["역사","제도","추억"],"themeColor":"bg-neon-green"},{"id":"1980-1","word":"과과","era":"1980년대","meaning":"1980년대 대학생들이 각 학과의 대표인 '과 대표'를 재치 있고 친근하게 줄여 부르던 은어","example":"과과! 오늘 중간고사 끝나고 다 같이 동기들이랑 뒷풀이 가기로 했어?","tags":["대학생활","줄임말","대표"],"themeColor":"bg-neon-green"},{"id":"1980-2","word":"범생이","era":"1980년대","meaning":"지나치게 모범적으로 공부만 하거나 학교 규칙에 지나칠 정도로 순종하는 학생을 친구들이 약간 귀여운 놀림조로 일컫던 말","example":"철수는 오락실도 한 번 안 가본 완전 백 퍼센트 범생이야.","tags":["학교생활","학생","모범생"],"themeColor":"bg-neon-blue"},{"id":"1980-3","word":"땡땡이","era":"1980년대","meaning":"수업 시간이나 직무 시간을 승인 없이 제멋대로 빠져나와 밖에서 노는 행동을 가리키던 학창시절 대유행 은어","example":"날씨가 너무 화창한데 마지막 자율학습 시간에는 땡땡이 치고 떡볶이 먹으러 가자.","tags":["탈출","학창시절","유행어"],"themeColor":"bg-neon-pink"},{"id":"1980-4","word":"골 때린다","era":"1980년대","meaning":"어떤 대상의 행동이 너무나 황당하고 어이가 없어 폭소를 자아내거나 골치가 살짝 아플 때 표현하는 당대의 표준적 감탄 수식어","example":"갑자기 한겨울에 반바지 입고 나타나다니 걔 행동 정말 골 때린다.","tags":["황당","유머","리액션"],"themeColor":"bg-neon-orange"},{"id":"1980-5","word":"꼽사리","era":"1980년대","meaning":"타인들의 대화나 일 또는 놀이 판에 정식 초청이나 지분도 없이 괜히 옆에서 끼어들어 한몫 거들거나 참견하는 얌체 같은 행동","example":"우리가 진지하게 논의하는 중이니까 넌 중간에 꼽사리 끼어서 왈가왈부하지 마.","tags":["참견","인간관계","말장난"],"themeColor":"bg-neon-green"},{"id":"1980-6","word":"미팅","era":"1980년대","meaning":"대학 문화와 제과점 문화가 융합되면서 큰 화제를 몰고 온 다대다 소개팅 방식. 자신의 물건을 골라 커플을 매칭하던 것이 이색적 유행","example":"내일 옆 학교 이과 대학생들이랑 빵집에서 주말 미팅이 약속되어 있어서 벌써 설레.","tags":["대학문화","연애","소개팅"],"themeColor":"bg-neon-blue"},{"id":"1980-7","word":"야타족","era":"1980년대","meaning":"1980년대 후반 부모의 부를 과시하며 고급 승용차를 끌고 강남 길거리에 나선 후, 마음에 드는 여성에게 \"야 타!\"를 외쳐 즉석 만남을 주도하던 일파","example":"압구정동 로데오 거리에 나가면 주말 저녁에 야타족들이 진짜 엄청 많대.","tags":["사회현상","부유층","오렌지족"],"themeColor":"bg-neon-pink"},{"id":"1980-8","word":"삐삐","era":"1980년대","meaning":"1980년대 후반에 출시되어 젊은이들의 연락 문화를 획기적으로 바꾼 무선 호출기. 특유의 알림음에서 유래한 친숙한 애칭","example":"공중전화 찾으면 내 삐삐로 음성 사서함 꼭 먼저 확인해 줘.","tags":["IT기술","통신","신조어"],"themeColor":"bg-neon-orange"},{"id":"1980-9","word":"마이마이","era":"1980년대","meaning":"국산 휴대용 카세트 플레이어의 고유 명사이자 대명사로, 가방에 넣고 다니며 나만의 음악 세계에 몰입하게 하던 젊은이들의 명품","example":"생일 선물로 마이마이를 선물 받고 기뻐서 밤새 좋아하는 테이프를 들었어.","tags":["카세트","음악","명품"],"themeColor":"bg-neon-green"},{"id":"1980-10","word":"디스코텍","era":"1980년대","meaning":"현란한 음악과 조명이 가득한 지하 공간으로, 당시 대학생들이 스트레스를 해소하고 화려한 춤사위를 선보이던 대중적 사교 댄스 홀","example":"시험이 끝난 기념으로 다 같이 시내 디스코텍에 가기로 예약해 놓았지.","tags":["댄스","놀이","스트레스"],"themeColor":"bg-neon-blue"},{"id":"1980-11","word":"롤러장","era":"1980년대","meaning":"바퀴 네 개 달린 롤러스케이트를 타며 경쾌한 신스팝 음악을 감상하고 이성과 손을 잡고 트랙을 돌던 중고등학생들의 최대 유흥 공간","example":"주말만 되면 멋진 옷을 차려입고 롤러장에서 스케이트 기술을 뽐내는 친구들이 많았다.","tags":["스케이트","청소년","음악"],"themeColor":"bg-neon-pink"},{"id":"1980-12","word":"비디오방","era":"1980년대","meaning":"집에서 보기 힘든 최신 영화 카세트 테이프를 아늑한 공간에서 대형 화면으로 골라볼 수 있어 인기를 끌기 시작한 초기 영화방 서비스","example":"홍콩 액션 영화 신작이 들어왔다길래 방과 후에 비디오방으로 바로 달려갔어.","tags":["영화","비디오","연인"],"themeColor":"bg-neon-orange"},{"id":"1980-13","word":"시티보이","era":"1980년대","meaning":"세련되고 서구적인 도시적 패션 스타일과 음악, 스포츠 등 고유한 취미 생활을 우아하게 영위하던 80년대 후반의 멋쟁이 청년들","example":"깔끔한 셔츠와 면바지를 입은 그의 모습은 전형적인 시티보이 스타일이야.","tags":["스타일","패션","라이프"],"themeColor":"bg-neon-green"},{"id":"1980-14","word":"비밀과외","era":"1980년대","meaning":"국가의 전면 과외 금지 조치에도 불구하고 자녀 학업을 위해 은밀히 고액을 지불하며 성행하던 단속 대피형 학업 형태","example":"우리 옆집에서는 혹시 과외단속에 걸릴까 봐 밤늦게 비밀과외를 한대.","tags":["사회상","교육","단속"],"themeColor":"bg-neon-blue"},{"id":"1980-15","word":"얄개시대","era":"1980년대","meaning":"학창 시절 청소년들의 유쾌하고 풋풋한 에피소드와 장난기 서린 삶을 추억하고 미화하여 부르던 문학 및 대중적 고유어","example":"그 친구와 나누던 편지를 다시 읽어보니 우리들의 찬란했던 얄개시대가 떠오른다.","tags":["추억","청소년","학창시절"],"themeColor":"bg-neon-pink"},{"id":"1980-16","word":"방가루","era":"1980년대","meaning":"80년대 PC통신의 싹이 트기 전 수줍게 구어로 유행했던 \"반갑습니다\"의 깜찍한 변형어이자 신조어","example":"아침에 교실에 들어서며 친구들에게 \"모두들 방가루!\" 하며 쾌활하게 손을 흔들었다.","tags":["인사","학생","유행어"],"themeColor":"bg-neon-orange"},{"id":"1980-17","word":"모래시계 세대","era":"1980년대","meaning":"80년대 대학가 민주화 운동과 급격한 정치적 격동기 속에서 청춘을 불태우고 무거운 역사의식을 공유하며 고민하던 지성인 세대","example":"아버지는 본인의 치열했던 청년기를 가리켜 모래시계 세대라고 설명해 주셨어.","tags":["역사","민주화","대학생"],"themeColor":"bg-neon-green"},{"id":"1980-18","word":"신세대","era":"1980년대","meaning":"전통적인 효 사상이나 보수적 가치에 전면 의문을 제기하며, 개인의 풍요와 개성 표현을 당당하게 내세우기 시작한 80년대 후반 청년들","example":"당시 언론들은 소비 지향적이고 톡톡 튀는 신세대의 출현에 깊은 관심을 보였다.","tags":["세대","개성","트렌드"],"themeColor":"bg-neon-blue"},{"id":"1980-19","word":"구로공단","era":"1980년대","meaning":"80년대 대한민국 경제 발전의 견인차 역할을 한 여공들과 남동생의 학비를 책임지던 오빠들의 눈물겨운 헌신과 공장 노동 문화의 현장","example":"눈부신 빌딩 숲이 된 오늘의 거리를 보니 옛날 구로공단의 노동 가요 소리가 아련해지는군.","tags":["역사","노동","경제"],"themeColor":"bg-neon-pink"},{"id":"1980-20","word":"워크맨","era":"1980년대","meaning":"포터블 카세트 플레이어의 원조이자 대명사로, 음악을 들고 길거리를 다닐 수 있는 특권을 쥐어 준 젊은이들의 넘버원 로망 아이템","example":"청바지 뒷주머니에 워크맨을 찔러 넣고 좋아하는 팝 밴드의 음악을 재생했지.","tags":["IT기술","카세트","유행"],"themeColor":"bg-neon-orange"},{"id":"1990-1","word":"따봉","era":"1990년대","meaning":"매우 좋다는 뜻. 브라질어에서 유래했으며 광고를 통해 유행","example":"이번 주말 날씨 완전 따봉이야!","tags":["광고유행어","최상급","긍정"],"themeColor":"bg-neon-green"},{"id":"1990-2","word":"캡","era":"1990년대","meaning":"최고, 으뜸이라는 뜻. 우두머리를 뜻하는 캡틴에서 유래","example":"이 노래 완전 캡이다!","tags":["최상급","감탄"],"themeColor":"bg-neon-blue"},{"id":"1990-3","word":"방가방가","era":"1990년대","meaning":"반갑다는 뜻. PC통신 시절 채팅에서 주로 사용","example":"님들 하이루~ 방가방가","tags":["PC통신","인사"],"themeColor":"bg-neon-pink"},{"id":"1990-4","word":"킹카 / 퀸카","era":"1990년대","meaning":"외모가 매우 뛰어나거나 인기 있는 남녀를 지칭하는 말","example":"오늘 미팅에 우리 학교 킹카 나온대.","tags":["외모","미팅","인기"],"themeColor":"bg-neon-orange"},{"id":"1990-5","word":"당근이지","era":"1990년대","meaning":"\"당연하지\"를 비슷한 발음인 당근으로 바꿔 부른 말","example":"오늘 PC방 갈 거지? - 당근이지!","tags":["동의","말장난","유머"],"themeColor":"bg-neon-green"},{"id":"1990-6","word":"오렌지족","era":"1990년대","meaning":"1990년대 초반, 부모의 부를 바탕으로 사치스러운 소비 생활을 하던 강남의 젊은이들","example":"압구정동에 가면 오렌지족들이 많았지.","tags":["사회현상","소비","문화"],"themeColor":"bg-neon-orange"},{"id":"1990-7","word":"헐","era":"1990년대","meaning":"어이없거나 놀랐을 때, 당황했을 때 내뱉는 감탄사","example":"헐, 내 지갑 어디 갔지?","tags":["놀람","당황","감탄"],"themeColor":"bg-neon-pink"},{"id":"1990-8","word":"하이루","era":"1990년대","meaning":"\"Hi\"와 \"루\"의 합성어로 PC통신에서 쓰던 인사말","example":"다들 하이루~ 오늘 기분 어때요?","tags":["인사","PC통신","채팅"],"themeColor":"bg-neon-blue"},{"id":"1990-9","word":"썰렁하다","era":"1990년대","meaning":"농담이나 분위기가 재미없고 가라앉았을 때 쓰는 표현","example":"네 농담 진짜 썰렁하다...","tags":["분위기","유머실패"],"themeColor":"bg-neon-green"},{"id":"1990-10","word":"울트라캡숑","era":"1990년대","meaning":"\"울트라(최고)\" + \"캡(최고)\" + \"숑(강조)\"이 결합되어 엄청나게 좋다는 뜻","example":"그 영화 완전 울트라캡숑 재밌어!","tags":["최상급","강조","감탄"],"themeColor":"bg-neon-orange"},{"id":"1990-11","word":"X세대","era":"1990년대","meaning":"기존의 가치관을 거부하고 개인주의와 개성을 중시하던 1990년대의 신세대","example":"우리는 개성을 존중하는 X세대야.","tags":["세대","문화","트렌드"],"themeColor":"bg-neon-pink"},{"id":"1990-12","word":"지대","era":"1990년대","meaning":"\"제대로\"를 변형한 말로, \"매우\", \"진짜\"라는 뜻의 강조어","example":"오늘 날씨 지대 덥다.","tags":["강조","은어"],"themeColor":"bg-neon-blue"},{"id":"1990-13","word":"불끈","era":"1990년대","meaning":"힘이 나거나 화가 날 때의 의태어를 채팅에서 감정표현으로 사용","example":"나 지금 완전 열받았어 (불끈)","tags":["감정표현","PC통신"],"themeColor":"bg-neon-green"},{"id":"1990-14","word":"야타족","era":"1990년대","meaning":"외제차를 타고 다니며 길가는 여성에게 \"야 타!\"라고 하며 데이트를 신청하던 이들","example":"90년대 뉴스에는 야타족 문제가 자주 나왔지.","tags":["사회현상","문화"],"themeColor":"bg-neon-orange"},{"id":"1990-15","word":"안녕바다","era":"1990년대","meaning":"당시 인기 있던 인사말 중 하나. 별바다 등 낭만적인 단어 조합이 유행","example":"모두들 안녕바다~","tags":["PC통신","감성"],"themeColor":"bg-neon-pink"},{"id":"1990-16","word":"즐","era":"1990년대","meaning":"\"즐거운 하루 되세요\"의 약자였으나, 점차 무성의한 답변이나 대화 거부를 나타낼 때 상대방을 놀리는 의미로 급변한 통신 외계어","example":"공부나 해라 - 즐, 네가 뭔 상관인데?","tags":["PC통신","도발","거부"],"themeColor":"bg-neon-blue"},{"id":"1990-17","word":"번개","era":"1990년대","meaning":"PC통신 채팅창에서 만난 회원들이 \"번개처럼 빠른 시간 내에 지금 만나자\"며 급히 추진하던 당일 오프라인 정기외 만남","example":"게시판에 서울 정모 번개 글이 올라왔는데 참여하실 분 구합니다.","tags":["PC통신","모임","즉석만남"],"themeColor":"bg-neon-green"},{"id":"1990-18","word":"담다디","era":"1990년대","meaning":"당시 전국을 뒤흔든 댄스 가요 제목에서 착안해, 신나고 흥겨운 분위기나 유쾌하게 장난치는 행동을 묘사하던 의성어적 은어","example":"오늘 기분이 너무 최고라 다 같이 담다디 춤이라도 춰야겠어.","tags":["가요","춤","유행어"],"themeColor":"bg-neon-orange"},{"id":"1990-19","word":"컴맹","era":"1990년대","meaning":"가정용 PC와 초고속 인터넷 보급 초기에 컴퓨터를 켤 줄도 모르는 정보화 소외 계층을 우스개로 부르던 사회적 신조어","example":"우리 삼촌은 마우스를 화면에 대고 누르는 완전 컴맹이셔.","tags":["컴퓨터","사회현상","초보"],"themeColor":"bg-neon-pink"},{"id":"1990-20","word":"보디가드","era":"1990년대","meaning":"당시 전설적인 헐리우드 흥행 영화 제목에서 유래하여, 친구나 좋아하는 사람을 뒤에서 졸졸 따라다니며 경호해 주는 사람을 부르던 애칭","example":"철수는 매일 아침 영희의 보디가드를 자처하며 등굣길을 함께해.","tags":["영화","경호","친구"],"themeColor":"bg-neon-blue"},{"id":"2000-1","word":"킹왕짱","era":"2000년대","meaning":"매우 대단하거나, 최고라는 뜻을 강조할 때 쓰는 말","example":"이번 기말고사 수학 점수 완전 킹왕짱이야!","tags":["싸이월드","최상급","감탄"],"themeColor":"bg-neon-orange"},{"id":"2000-2","word":"지못미","era":"2000년대","meaning":"\"지켜주지 못해 미안해\"의 줄임말. 굴욕적인 모습을 봤을 때 주로 사용","example":"바람 불어서 앞머리 다 까졌네... 지못미...","tags":["안습","동정","웃픔"],"themeColor":"bg-neon-pink"},{"id":"2000-3","word":"얼짱","era":"2000년대","meaning":"\"얼굴이 짱(최고)이다\"라는 뜻으로, 외모가 매우 뛰어난 사람","example":"저 선배 우리 학교 얼짱 출신이잖아.","tags":["외모","캠캠","하두리"],"themeColor":"bg-neon-blue"},{"id":"2000-4","word":"안습","era":"2000년대","meaning":"\"안구에 습기 차다\"의 줄임말. 눈물이 날 정도로 안타깝다는 뜻","example":"오늘 지각해서 선생님한테 혼났어. 완전 안습.","tags":["슬픔","안타까움"],"themeColor":"bg-neon-blue"},{"id":"2000-5","word":"훈남 / 훈녀","era":"2000년대","meaning":"보기만 해도 마음이 훈훈해지는 매력적인 남녀","example":"이번에 새로 온 알바생 완전 훈남이야.","tags":["외모","칭찬","매력"],"themeColor":"bg-neon-green"},{"id":"2000-6","word":"뭥미","era":"2000년대","meaning":"\"뭐임\"을 빠르게 치다가 발생한 오타에서 유래. 황당할 때 쓴다.","example":"이게 대체 뭥미? 말도 안 돼.","tags":["황당","오타","의문"],"themeColor":"bg-neon-orange"},{"id":"2000-7","word":"엄친아","era":"2000년대","meaning":"\"엄마 친구 아들\"의 줄임말. 공부도 잘하고 외모도 뛰어난 완벽한 사람","example":"내 짝꿍은 완전 엄친아야. 못하는 게 없어.","tags":["비교","완벽","부러움"],"themeColor":"bg-neon-pink"},{"id":"2000-8","word":"솔까말","era":"2000년대","meaning":"\"솔직히 까놓고 말해서\"의 줄임말","example":"솔까말 내가 너보다 게임은 잘하지.","tags":["솔직","고백","팩트"],"themeColor":"bg-neon-blue"},{"id":"2000-9","word":"OTL","era":"2000년대","meaning":"사람이 무릎을 꿇고 좌절한 모습을 알파벳으로 표현한 것","example":"이번 시험도 망했다... OTL","tags":["좌절","슬픔","이모티콘"],"themeColor":"bg-neon-green"},{"id":"2000-10","word":"넘사벽","era":"2000년대","meaning":"\"넘을 수 없는 4차원의 벽\"의 줄임말. 비교할 수 없을 정도로 차이가 날 때","example":"김연아의 스케이팅 실력은 진짜 넘사벽이야.","tags":["비교불가","최상급","존경"],"themeColor":"bg-neon-orange"},{"id":"2000-11","word":"레알","era":"2000년대","meaning":"\"Real\"을 보이는 대로 읽은 것. \"진짜\", \"정말\"이라는 뜻","example":"이 아이스크림 레알 맛있다.","tags":["진짜","강조","리얼"],"themeColor":"bg-neon-pink"},{"id":"2000-12","word":"듣보잡","era":"2000년대","meaning":"\"듣지도 보지도 못한 잡것\"의 줄임말. 유명하지 않은 사람이나 물건","example":"저 브랜드는 완전 듣보잡인데 가격만 비싸네.","tags":["무명","비하","생소함"],"themeColor":"bg-neon-blue"},{"id":"2000-13","word":"볼매","era":"2000년대","meaning":"\"볼수록 매력있다\"의 줄임말","example":"처음엔 별로였는데, 저 친구 완전 볼매네.","tags":["매력","칭찬","호감"],"themeColor":"bg-neon-green"},{"id":"2000-14","word":"지름신","era":"2000년대","meaning":"충동구매를 하게 만드는 신. 물건을 사고 싶은 강한 충동이 들 때","example":"어제 백화점 갔다가 지름신 강림해서 카드값 폭발했어.","tags":["쇼핑","충동구매","소비"],"themeColor":"bg-neon-orange"},{"id":"2000-15","word":"병크","era":"2000년대","meaning":"\"병신 같은 크리티컬\"의 줄임말. 아주 큰 실수나 어이없는 잘못을 뜻함","example":"이번 기획안에서 완전 병크 터뜨렸어...","tags":["실수","실패","후회"],"themeColor":"bg-neon-pink"},{"id":"2000-16","word":"초딩","era":"2000년대","meaning":"초등학생을 비하해 부르던 통신 은어이자, 나이에 상관없이 철없고 유치한 행동을 부끄럼 없이 일삼는 사람을 이르는 말","example":"나이 마흔 넘어서 길거리에서 떼를 쓰다니 진짜 초딩이 따로 없네.","tags":["인터넷","비하","유치함"],"themeColor":"bg-neon-blue"},{"id":"2000-17","word":"완소","era":"2000년대","meaning":"\"완전히 소중한\"의 줄임말로, 미니홈피나 인터넷 게시판에서 자신이 아끼고 특별히 사랑하는 대상을 강조하여 수식하던 표현","example":"그녀는 내 마음속 영원한 완소 여배우야.","tags":["인터넷","소중함","수식어"],"themeColor":"bg-neon-green"},{"id":"2000-18","word":"아웃오브안중","era":"2000년대","meaning":"\"Out of(벗어난)\"와 \"안중(눈 안)\"의 결합어. 시야나 마음에서 완전히 멀어져 더 이상 아무 관심도 가치도 두지 않는 대상","example":"시험이 코앞이라 취미 생활은 완전히 아웃오브안중 상태야.","tags":["외래어","무관심","조합어"],"themeColor":"bg-neon-orange"},{"id":"2000-19","word":"굴욕","era":"2000년대","meaning":"연예인이나 유명인의 찰나의 우스꽝스러운 표정이나 불리한 신체 비율 사진에 붙여 재미를 유발하던 유행어","example":"오늘 바람 때문에 내 앞머리가 완전히 뒤집혀서 굴욕 샷을 남기고 말았어.","tags":["사진","엽기","굴욕"],"themeColor":"bg-neon-pink"},{"id":"2000-20","word":"갑툭튀","era":"2000년대","meaning":"\"갑자기 툭 튀어나오다\"의 줄임말로, 평화롭던 상황에 예상하지 못한 인물이나 물체가 뜬금없이 나타났을 때 표현하는 말","example":"골목을 도는데 고양이 한 마리가 갑툭튀 해서 심장이 내려앉는 줄 알았어.","tags":["깜짝","돌발","상황"],"themeColor":"bg-neon-blue"},{"id":"2010-1","word":"갑분싸","era":"2010년대","meaning":"\"갑자기 분위기 싸해짐\"의 줄임말. 썰렁한 농담이나 행동으로 분위기가 식었을 때","example":"부장님이 아재개그 하셔서 완전 갑분싸 됐어.","tags":["분위기","정적","당황"],"themeColor":"bg-neon-blue"},{"id":"2010-2","word":"소확행","era":"2010년대","meaning":"소소하지만 확실한 행복. 일상에서 느낄 수 있는 작지만 확실한 기쁨","example":"퇴근하고 맥주 한 캔 마시는 게 나의 소확행이야.","tags":["행복","라이프스타일","힐링"],"themeColor":"bg-neon-green"},{"id":"2010-3","word":"TMI","era":"2010년대","meaning":"\"Too Much Information\"의 약자. 굳이 알고 싶지 않은 과한 정보","example":"나 오늘 아침에 바나나 먹었는데 화장실을... (아 TMI 그만!)","tags":["정보과잉","수다"],"themeColor":"bg-neon-orange"},{"id":"2010-4","word":"인싸 / 아싸","era":"2010년대","meaning":"인사이더(무리와 잘 어울리는 사람)와 아웃사이더(혼자 지내는 사람)","example":"저 친구 완전 핵인싸야, 모르는 사람이 없어.","tags":["사회생활","성향"],"themeColor":"bg-neon-pink"},{"id":"2010-5","word":"JMT (존맛탱)","era":"2010년대","meaning":"음식이 매우 맛있다는 뜻의 격한 표현","example":"이 마라탕 진짜 JMT... 매일 먹고 싶다.","tags":["음식","맛집","감탄"],"themeColor":"bg-neon-orange"},{"id":"2010-6","word":"뇌피셜","era":"2010년대","meaning":"뇌(Brain) + 오피셜(Official). 공식적인 사실이 아닌 자신의 생각이나 추측","example":"그거 기사 뜬 거 맞아? 완전 네 뇌피셜 아니야?","tags":["추측","생각","비공식"],"themeColor":"bg-neon-blue"},{"id":"2010-7","word":"팩폭","era":"2010년대","meaning":"\"팩트 폭력\"의 줄임말. 사실을 말해서 상대방의 정곡을 찔러 아프게 하는 것","example":"너 통장 잔고 0원이잖아. - 아 팩폭 멈춰...","tags":["사실","정곡","직설"],"themeColor":"bg-neon-green"},{"id":"2010-8","word":"존버","era":"2010년대","meaning":"\"존나 버티기\"의 줄임말. 힘든 상황을 끝까지 버틴다는 뜻","example":"비트코인 떡상할 때까지 무조건 존버간다.","tags":["인내","버티기","가상화폐"],"themeColor":"bg-neon-pink"},{"id":"2010-9","word":"워라밸","era":"2010년대","meaning":"\"Work-Life Balance\"의 줄임말. 일과 삶의 균형을 중요시하는 태도","example":"이 회사는 연봉보다 워라밸이 최고야.","tags":["직장","라이프","가치관"],"themeColor":"bg-neon-blue"},{"id":"2010-10","word":"띵작","era":"2010년대","meaning":"\"명작\"의 모양이 비슷한 글자인 \"띵\"으로 바꾼 야민정음","example":"이 영화는 내 인생 띵작이야.","tags":["야민정음","명작","추천"],"themeColor":"bg-neon-orange"},{"id":"2010-11","word":"관종","era":"2010년대","meaning":"\"관심 종자\"의 줄임말. 다른 사람들의 관심을 받기 위해 무리한 행동을 하는 사람","example":"저 사람 또 SNS에 이상한 글 올렸네, 완전 관종이야.","tags":["관심","SNS","비판"],"themeColor":"bg-neon-green"},{"id":"2010-12","word":"탕진잼","era":"2010년대","meaning":"재산을 다 탕진하는 재미. 소소한 물건을 낭비하듯 사며 스트레스를 푸는 것","example":"오늘 다이소 가서 탕진잼 하고 왔어.","tags":["소비","스트레스해소","재미"],"themeColor":"bg-neon-pink"},{"id":"2010-13","word":"낄끼빠빠","era":"2010년대","meaning":"\"낄 때 끼고 빠질 때 빠져라\"의 줄임말. 눈치 있게 행동하라는 뜻","example":"거긴 우리가 낄 자리가 아니야, 낄끼빠빠 하자.","tags":["눈치","처세술","센스"],"themeColor":"bg-neon-blue"},{"id":"2010-14","word":"이생망","era":"2010년대","meaning":"\"이번 생은 망했다\"의 줄임말. 일이 뜻대로 풀리지 않을 때 자조적으로 하는 말","example":"수능 망쳤어... 난 이생망이야.","tags":["좌절","포기","자조"],"themeColor":"bg-neon-orange"},{"id":"2010-15","word":"취존","era":"2010년대","meaning":"\"취향 존중\"의 줄임말. 각자의 다양한 취향을 인정하고 존중하자는 뜻","example":"난 민트초코 좋아해. 취존 부탁!","tags":["취향","존중","개인주의"],"themeColor":"bg-neon-green"},{"id":"2010-16","word":"영고","era":"2010년대","meaning":"\"영원히 고통받는\"의 줄임말. 과거의 흑역사나 난감한 별명이 인터넷상에 평생 박제되어 지속적으로 놀림받는 대상","example":"그 선배는 대학 시절 춤춘 영상 때문에 평생 영고 라인을 탈 것 같아.","tags":["인터넷","고통","박제"],"themeColor":"bg-neon-blue"},{"id":"2010-17","word":"심쿵","era":"2010년대","meaning":"\"심장이 쿵할 정도로 설렌다\"의 줄임말. 매우 사랑스럽거나 매력적인 대상, 이성을 마주해 설렘과 큰 충격을 느낄 때 쓰는 말","example":"아기 고양이가 나를 보며 하품을 하는데 진짜 너무 심쿵했어.","tags":["설렘","감격","칭찬"],"themeColor":"bg-neon-green"},{"id":"2010-18","word":"사이다","era":"2010년대","meaning":"막혔던 상황이 시원하게 뚫리거나, 억울하고 답답하던 일들이 통쾌하게 해결되어 톡 쏘는 탄산음료를 마신 기분일 때 쓰는 대중어","example":"악플러들에게 시원하게 일침을 가하는 사이다 대처법이 큰 호응을 얻었어.","tags":["시원","통쾌","해결"],"themeColor":"bg-neon-orange"},{"id":"2010-19","word":"궁예질","era":"2010년대","meaning":"아무런 뚜렷한 증거나 개연성 없이 타인의 생각이나 사생활, 동기를 독자적으로 지레넘겨짚고 확신해 비난하는 어리석은 태도","example":"아직 확정된 사실도 없는데 댓글로 멋대로 궁예질 하는 행위는 자제하자.","tags":["추측","비난","역사비유"],"themeColor":"bg-neon-pink"},{"id":"2010-20","word":"꿀잼","era":"2010년대","meaning":"꿀처럼 아주 달콤하고 짜릿하게 매우 재미있다는 뜻과 전혀 재미가 없다는 뜻의 노잼(No 재미)이 융합된 대표 신조어","example":"이번에 개봉한 신작 영화는 진짜 시종일관 꿀잼이라 시간 가는 줄 몰랐어.","tags":["재미","강조","대중적"],"themeColor":"bg-neon-blue"},{"id":"2020-1","word":"중꺾마","era":"2020년대","meaning":"\"중요한 것은 꺾이지 않는 마음\"의 줄임말. 포기하지 않는 태도를 의미","example":"이번 시험 망쳤지만 포기 안 해. 중꺾마!","tags":["의지","열정","밈"],"themeColor":"bg-neon-blue"},{"id":"2020-2","word":"폼 미쳤다","era":"2020년대","meaning":"기량이나 상태(Form)가 비정상적으로 뛰어나거나 대단하다는 뜻","example":"오늘 손흥민 드리블 폼 미쳤다 진짜.","tags":["칭찬","최상급","감탄"],"themeColor":"bg-neon-green"},{"id":"2020-3","word":"너 T야?","era":"2020년대","meaning":"MBTI에서 사고형(T)이냐고 묻는 말. 상대방이 공감해주지 않고 이성적으로만 반응할 때 서운함을 담아 하는 말","example":"내가 아파서 속상하다는데 병원 가라니... 너 T야?","tags":["MBTI","공감","유머"],"themeColor":"bg-neon-blue"},{"id":"2020-4","word":"완전 럭키비키잖아🍀","era":"2020년대","meaning":"아이브 장원영의 초긍정적 사고방식(원영적 사고)에서 유래. 안 좋은 상황에서도 오히려 좋다고 긍정적으로 생각하는 태도","example":"빵 사러 갔는데 다 품절됐네? 덕분에 다이어트 하고 완전 럭키비키잖아!","tags":["긍정","원영적사고","행복"],"themeColor":"bg-neon-green"},{"id":"2020-5","word":"긁?","era":"2020년대","meaning":"\"너 긁혔어?\"(자존심 상했어? 화났어?)의 줄임말. 상대방을 도발하거나 놀릴 때 사용","example":"게임 지고 나서 변명하는 거 보니까 너 긁혔네 ㅋㅋ 긁?","tags":["도발","도파민","게임"],"themeColor":"bg-neon-pink"},{"id":"2020-6","word":"오운완","era":"2020년대","meaning":"\"오늘 운동 완료\"의 줄임말. SNS에 운동 인증샷을 올릴 때 쓰는 해시태그","example":"#오운완 오늘 하체 부수기 성공!","tags":["자기관리","갓생","SNS"],"themeColor":"bg-neon-blue"},{"id":"2020-7","word":"알잘딱깔센","era":"2020년대","meaning":"\"알아서 잘 딱 깔끔하고 센스있게\"의 줄임말","example":"이번 프로젝트 기획안 알잘딱깔센으로 부탁해.","tags":["일잘러","센스","부탁"],"themeColor":"bg-neon-orange"},{"id":"2020-8","word":"갓생","era":"2020년대","meaning":"God(신) + 인생. 매우 부지런하고 계획적으로 열심히 사는 모범적인 삶","example":"내일부터 아침 6시에 일어나서 운동하고 갓생 산다.","tags":["자기계발","루틴","목표"],"themeColor":"bg-neon-green"},{"id":"2020-9","word":"추구미","era":"2020년대","meaning":"\"추구하다\" + \"미(美)\". 자신이 지향하고 닮고 싶은 이미지나 스타일","example":"저 연예인 패션이 요즘 내 추구미야.","tags":["스타일","취향","워너비"],"themeColor":"bg-neon-pink"},{"id":"2020-10","word":"억까","era":"2020년대","meaning":"\"억지로 까다\"의 줄임말. 정당한 이유 없이 억지로 트집을 잡아 비난하는 것","example":"아니 내가 언제 그랬어? 이거 완전 억까네.","tags":["불평","비난","억울함"],"themeColor":"bg-neon-blue"},{"id":"2020-11","word":"찢었다","era":"2020년대","meaning":"무대를 장악했거나, 무언가를 엄청나게 잘 해냈을 때 감탄사로 쓰임","example":"와, 방금 무대 완전 찢었다...","tags":["감탄","최고","성공"],"themeColor":"bg-neon-orange"},{"id":"2020-12","word":"어쩔티비","era":"2020년대","meaning":"\"어쩌라고 티비나 봐\"의 줄임말. 상대방의 말을 무시하거나 짜증나게 할 때 씀","example":"너 오늘 왜 이렇게 늦었어? - 어쩔티비~","tags":["초딩","무시","도발"],"themeColor":"bg-neon-green"},{"id":"2020-13","word":"누칼협","era":"2020년대","meaning":"\"누가 칼 들고 협박함?\"의 줄임말. 본인이 선택한 일에 대해 불평할 때 비꼬는 말","example":"주식 떨어져서 미치겠다. - 누칼협? 네가 샀잖아.","tags":["팩폭","비꼬기","선택"],"themeColor":"bg-neon-pink"},{"id":"2020-14","word":"점메추","era":"2020년대","meaning":"\"점심 메뉴 추천\"의 줄임말","example":"오늘 뭐 먹지? 맛있는 걸로 점메추 좀 해줘.","tags":["음식","직장인","일상"],"themeColor":"bg-neon-blue"},{"id":"2020-15","word":"디토합니다","era":"2020년대","meaning":"Ditto(나도, 마찬가지). 앞 사람의 의견에 100% 동의할 때 쓰는 말","example":"오늘 회식은 소고기 어때요? - 전적으로 디토합니다!","tags":["동의","공감","트렌드"],"themeColor":"bg-neon-orange"},{"id":"2020-16","word":"무물","era":"2020년대","meaning":"\"무엇이든 물어보세요\"의 줄임말로, SNS 플랫폼의 질문 기능이나 팬들과 소통하며 허심탄회하게 답변을 주고받는 행위","example":"오늘 심심하니까 인스타그램 스토리에서 무물 진행할게요!","tags":["SNS","소통","인스타그램"],"themeColor":"bg-neon-pink"},{"id":"2020-17","word":"스불재","era":"2020년대","meaning":"\"스스로 불러온 재앙\"의 줄임말. 타인의 강요 없이 오직 본인의 선택이나 욕심으로 무리한 일을 벌였다가 힘든 상황에 처했을 때 자조적으로 이르는 말","example":"마감 직전에 과제 세 개를 한 번에 하겠다고 미뤄둔 건 완전 스불재야.","tags":["후회","선택","자조"],"themeColor":"bg-neon-blue"},{"id":"2020-18","word":"군침이 싹 도네","era":"2020년대","meaning":"애니메이션 캐릭터 루피의 광기 서린 표정 짤에서 유래하여, 구미가 당기거나 흥미진진한 대상을 발견했을 때 기대감을 갖고 쓰는 유행어","example":"새로 나온 최신 게임 영상을 보니까 벌써부터 군침이 싹 도네.","tags":["밈","인기","캐릭터"],"themeColor":"bg-neon-green"},{"id":"2020-19","word":"식집사","era":"2020년대","meaning":"\"식물\"과 \"집사\"의 합성어로, 정성스럽게 정과 사랑을 쏟으며 반려식물을 키우고 인테리어를 가꾸는 사람들을 뜻하는 건강한 신조어","example":"베란다에 화분을 가득 들여놓았더니 나도 영락없는 식집사가 다 되었구나.","tags":["반려식물","힐링","취미"],"themeColor":"bg-neon-orange"},{"id":"2020-20","word":"많관부","era":"2020년대","meaning":"\"많은 관심 부탁드립니다\"의 줄임말로, 자신의 창작물이나 행사, 이벤트, 홍보 글을 대중에게 소개하면서 애정을 요청할 때 쓰는 글","example":"이번에 우리 동아리에서 전시회를 엽니다. 모두들 많관부!","tags":["부탁","홍보","소통"],"themeColor":"bg-neon-blue"},{"id":"1970-21","word":"아베크족","era":"1970년대","meaning":"프랑스어 '아베크(avec·함께)'에서 온 말로, 다정하게 데이트하는 연인 한 쌍을 이르던 말","example":"고궁에 가면 아베크족들이 손을 꼭 잡고 걷는 모습이 참 보기 좋았지.","tags":["연애","낭만"],"themeColor":"bg-neon-blue"},{"id":"1970-22","word":"하이틴","era":"1970년대","meaning":"10대 후반의 청소년을 멋스럽게 부르던 말로, 하이틴 영화·하이틴 잡지가 큰 인기를 끌었다","example":"그 시절 하이틴 영화 보러 극장 앞에 줄을 길게 섰었잖아.","tags":["청춘","영화"],"themeColor":"bg-neon-pink"},{"id":"1970-23","word":"쎄시봉","era":"1970년대","meaning":"서울 무교동에 있던 음악감상실 이름으로, 통기타 가수들의 산실이자 청년 문화의 성지였다","example":"쎄시봉에서 트윈폴리오 노래를 처음 듣고 밤새 잠을 못 이뤘다니까.","tags":["음악","청년문화"],"themeColor":"bg-neon-orange"},{"id":"1970-24","word":"별밤","era":"1970년대","meaning":"라디오 프로그램 '별이 빛나는 밤에'의 애칭으로, 밤마다 사연과 신청곡을 들으며 청춘을 달랬다","example":"숙제 미뤄두고 이불 속에서 별밤 들으며 엽서 사연 읽어주길 기다렸지.","tags":["라디오","추억"],"themeColor":"bg-neon-green"},{"id":"1970-25","word":"교련복","era":"1970년대","meaning":"고등학교 군사훈련 과목인 교련 시간에 입던 얼룩무늬 훈련복","example":"교련복 입고 목총 들고 운동장에서 제식훈련 받던 게 엊그제 같네.","tags":["학교","교복"],"themeColor":"bg-neon-blue"},{"id":"1970-26","word":"국민학교","era":"1970년대","meaning":"지금의 초등학교를 부르던 옛 이름으로, 1996년에 초등학교로 바뀌었다","example":"우리 국민학교 동창들 이번 달에 모이기로 했어.","tags":["학교","추억"],"themeColor":"bg-neon-pink"},{"id":"1970-27","word":"도끼빗","era":"1970년대","meaning":"도끼 모양의 큰 빗으로, 멋쟁이 청년들이 뒷주머니에 꽂고 다니며 수시로 머리를 빗었다","example":"뒷주머니에 도끼빗 꽂고 다녀야 멋쟁이 소리를 들었지.","tags":["패션","멋"],"themeColor":"bg-neon-orange"},{"id":"1970-28","word":"포크송","era":"1970년대","meaning":"통기타 반주에 서정적인 가사를 얹은 노래로, 1970년대 청년 문화의 상징이었다","example":"모닥불 피워놓고 다 같이 포크송 부르던 밤이 그립네.","tags":["음악","통기타"],"themeColor":"bg-neon-green"},{"id":"1970-29","word":"음악다방 DJ","era":"1970년대","meaning":"음악다방 유리 부스 안에서 신청곡을 틀고 사연을 읽어주던 디스크자키","example":"DJ한테 쪽지로 신청곡 넣고 그 노래 나오길 두근두근 기다렸지.","tags":["다방","음악"],"themeColor":"bg-neon-blue"},{"id":"1970-30","word":"브라보콘","era":"1970년대","meaning":"1970년에 나온 국내 최초의 콘 아이스크림으로, '12시에 만나요'라는 CM송이 유명했다","example":"12시에 만나요 브라보콘~ 그 노래는 지금도 안 잊혀.","tags":["간식","광고"],"themeColor":"bg-neon-pink"},{"id":"1970-31","word":"삼립호빵","era":"1970년대","meaning":"'찬바람이 싸늘하게'라는 광고와 함께 겨울철 국민 간식이 된 찐빵","example":"겨울이면 김이 모락모락 나는 호빵 하나로 손도 녹이고 배도 채웠지.","tags":["간식","겨울"],"themeColor":"bg-neon-orange"},{"id":"1970-32","word":"로보트 태권V","era":"1970년대","meaning":"1976년 개봉한 국산 로봇 만화영화로, 온 동네 아이들을 극장 앞에 줄 세웠다","example":"태권V 보러 형 손잡고 극장 갔던 날이 아직도 생생해.","tags":["만화","영화"],"themeColor":"bg-neon-green"},{"id":"1970-33","word":"선데이서울","era":"1970년대","meaning":"1968년 창간된 주간 오락잡지로, 연예·스포츠 소식의 보물창고였다","example":"이발소 가면 선데이서울부터 집어 들고 차례를 기다렸지.","tags":["잡지","연예"],"themeColor":"bg-neon-blue"},{"id":"1970-34","word":"어깨동무","era":"1970년대","meaning":"1967년 창간된 어린이 잡지로, 부록 딸린 새 호가 나오는 날을 손꼽아 기다렸다","example":"어깨동무 부록 조립하느라 밤늦게까지 풀칠하던 기억이 나네.","tags":["잡지","어린이"],"themeColor":"bg-neon-pink"},{"id":"1970-35","word":"고교야구","era":"1970년대","meaning":"황금사자기·청룡기 같은 고교야구 대회가 온 국민의 관심사였던 시절의 국민 스포츠","example":"모교가 고교야구 결승 가던 날은 온 동네가 라디오 앞에 모였지.","tags":["스포츠","응원"],"themeColor":"bg-neon-orange"},{"id":"1970-36","word":"혼분식 장려","era":"1970년대","meaning":"쌀을 아끼자며 보리·밀가루 음식을 권장하던 운동으로, 도시락 잡곡 검사까지 있었다","example":"도시락 검사 때문에 꽁보리밥 위에만 쌀밥 살짝 덮어 갔다가 들켰지 뭐야.","tags":["시대상","도시락"],"themeColor":"bg-neon-green"},{"id":"1970-37","word":"잘살아보세","era":"1970년대","meaning":"새마을운동을 상징하는 노래이자 구호로, 새벽마다 마을 확성기에서 울려 퍼졌다","example":"새벽종이 울렸네~ 하는 노래 들으며 온 동네가 골목길을 쓸었지.","tags":["시대상","새마을"],"themeColor":"bg-neon-blue"},{"id":"1970-38","word":"버스 안내양","era":"1970년대","meaning":"만원 버스에서 요금을 받고 '오라이!'를 외치며 문을 두드리던 버스 승무원","example":"콩나물시루 같은 버스에서 안내양이 오라이 외치면 그제야 출발했지.","tags":["직업","교통"],"themeColor":"bg-neon-pink"},{"id":"1970-39","word":"오라이","era":"1970년대","meaning":"영어 '올라잇(all right)'에서 온 말로, 버스 안내양이 출발해도 좋다는 뜻으로 외치던 신호","example":"오라이~ 소리와 함께 버스 문을 탕탕 두드리던 소리가 들리는 듯하네.","tags":["교통","유행어"],"themeColor":"bg-neon-orange"},{"id":"1970-40","word":"월부","era":"1970년대","meaning":"물건값을 다달이 나눠 내는 할부의 옛말로, 월부 책장수·월부 재봉틀이 흔했다","example":"백과사전 한 질을 월부로 들여놓고 삼 년을 갚았다니까.","tags":["생활","경제"],"themeColor":"bg-neon-green"},{"id":"1970-41","word":"전축","era":"1970년대","meaning":"레코드판을 올려 음악을 듣던 가정용 오디오로, 응접실의 자랑거리였다","example":"아버지가 아끼시던 전축에 몰래 판 올렸다가 혼쭐이 났지.","tags":["가전","음악"],"themeColor":"bg-neon-blue"},{"id":"1970-42","word":"테레비","era":"1970년대","meaning":"텔레비전을 정겹게 부르던 말로, 동네에 한 대뿐이라 저녁마다 마당에 모여 함께 봤다","example":"김일 레슬링 하는 날엔 테레비 있는 집 마당이 잔칫집이 됐지.","tags":["가전","동네"],"themeColor":"bg-neon-pink"},{"id":"1970-43","word":"만화가게","era":"1970년대","meaning":"동전 몇 닢에 만화책을 빌려 보던 동네 만화방으로, 아이들의 아지트였다","example":"만화가게에서 해 지는 줄 모르고 보다가 어머니한테 끌려 나왔지.","tags":["놀이","만화"],"themeColor":"bg-neon-orange"},{"id":"1970-44","word":"뻥튀기","era":"1970년대","meaning":"'뻥이요!' 소리와 함께 쌀·옥수수를 튀겨주던 간식이자 골목의 명물","example":"뻥이요 소리에 귀 막고 도망갔다가 튀밥 주우러 다시 달려갔지.","tags":["간식","골목"],"themeColor":"bg-neon-green"},{"id":"1970-45","word":"엿장수 맘대로","era":"1970년대","meaning":"엿장수가 가위질하며 엿을 마음대로 잘라주던 데서 나온 말로, 제멋대로 한다는 뜻","example":"그건 뭐 엿장수 맘대로구먼, 기준이 없어 기준이.","tags":["유행어","속담"],"themeColor":"bg-neon-blue"},{"id":"1970-46","word":"딱지치기","era":"1970년대","meaning":"종이를 접어 만든 딱지를 내리쳐 뒤집으면 따먹던 골목 대표 놀이","example":"아까운 새 공책 뜯어 딱지 접었다가 다 잃고 울었잖아.","tags":["놀이","골목"],"themeColor":"bg-neon-pink"},{"id":"1970-47","word":"십리사탕","era":"1970년대","meaning":"십 리를 걷는 동안 먹을 만큼 오래 녹는 왕눈깔사탕","example":"십리사탕 하나 물고 볼이 볼록한 채로 학교까지 걸어갔지.","tags":["간식","추억"],"themeColor":"bg-neon-orange"},{"id":"1970-48","word":"고바우 영감","era":"1970년대","meaning":"김성환 화백의 네 컷 시사만화 주인공으로, 신문 보는 재미의 절반이었다","example":"아버지는 신문 받으면 고바우 영감부터 찾아 보셨어.","tags":["만화","신문"],"themeColor":"bg-neon-green"},{"id":"1970-49","word":"여로","era":"1970년대","meaning":"1972년 방영된 일일연속극으로, 방송 시간이면 거리가 한산해질 만큼 인기였다","example":"여로 할 시간엔 온 식구가 밥상 물리고 테레비 앞에 모였지.","tags":["드라마","방송"],"themeColor":"bg-neon-blue"},{"id":"1970-50","word":"김일 박치기","era":"1970년대","meaning":"프로레슬러 김일 선수의 필살기로, 박치기 한 방이면 온 국민이 함성을 질렀다","example":"김일 선수 박치기 나오면 동네가 떠나가라 박수를 쳤다니까.","tags":["스포츠","영웅"],"themeColor":"bg-neon-pink"},{"id":"1980-21","word":"컬러TV","era":"1980년대","meaning":"1980년 컬러 방송이 시작되며 흑백 세상이 총천연색으로 바뀐 시대의 사건","example":"컬러TV 들여놓던 날, 온 식구가 화면만 뚫어져라 봤지.","tags":["가전","방송"],"themeColor":"bg-neon-orange"},{"id":"1980-22","word":"교복자율화","era":"1980년대","meaning":"1983년 중고생 교복을 자유복으로 바꾼 조치로, 아침마다 옷 고르는 고민이 생겼다","example":"교복자율화 되고 나니 입을 옷이 없어서 오히려 걱정이었어.","tags":["학교","시대상"],"themeColor":"bg-neon-green"},{"id":"1980-23","word":"두발자율화","era":"1980년대","meaning":"까까머리·단발머리 규제를 푼 조치로, 학생들이 처음으로 머리를 기를 수 있게 됐다","example":"두발자율화 됐다고 신나서 머리 길렀다가 아버지한테 혼났지.","tags":["학교","시대상"],"themeColor":"bg-neon-blue"},{"id":"1980-24","word":"야자","era":"1980년대","meaning":"'야간자율학습'의 줄임말로, 말은 자율인데 실제론 밤 10시까지 의무였던 학교의 추억","example":"야자 땡땡이치고 분식집 갔다가 담임한테 딱 걸렸잖아.","tags":["학교","공부"],"themeColor":"bg-neon-pink"},{"id":"1980-25","word":"호돌이","era":"1980년대","meaning":"1988년 서울올림픽 마스코트인 호랑이 캐릭터로, 온 나라의 사랑을 받았다","example":"호돌이 인형 하나 사달라고 문방구 앞에서 떼를 썼었지.","tags":["올림픽","캐릭터"],"themeColor":"bg-neon-orange"},{"id":"1980-26","word":"굴렁쇠 소년","era":"1980년대","meaning":"88올림픽 개회식에서 홀로 굴렁쇠를 굴리며 잔디밭을 가로지른 명장면","example":"굴렁쇠 소년 나올 때 경기장이 조용해지는데 소름이 쫙 돋았어.","tags":["올림픽","명장면"],"themeColor":"bg-neon-green"},{"id":"1980-27","word":"이산가족찾기","era":"1980년대","meaning":"1983년 KBS 생방송으로 138일간 이어진 이산가족 상봉 캠페인. '누가 이 사람을 아시나요'","example":"이산가족찾기 방송 보면서 온 식구가 같이 울었던 기억이 나.","tags":["방송","감동"],"themeColor":"bg-neon-blue"},{"id":"1980-28","word":"어린이회원","era":"1980년대","meaning":"1982년 프로야구 출범과 함께 생긴 구단 어린이 회원으로, 점퍼와 모자가 최고의 선물이었다","example":"어린이회원 점퍼 입고 학교 가면 다들 부러워했지.","tags":["야구","어린이"],"themeColor":"bg-neon-pink"},{"id":"1980-29","word":"전자오락실","era":"1980년대","meaning":"동전 넣고 갤러그·너구리를 하던 오락실로, 어머니들에겐 공공의 적이었다","example":"오락실에서 엄마한테 귀 잡혀 끌려 나온 게 한두 번이 아니야.","tags":["게임","놀이"],"themeColor":"bg-neon-orange"},{"id":"1980-30","word":"갤러그","era":"1980년대","meaning":"오락실 대표 슈팅 게임으로, 동전 하나로 최고 기록에 도전하는 재미가 쏠쏠했다","example":"갤러그 최고 점수 갈아치우고 어깨 힘주고 다녔지.","tags":["게임","오락실"],"themeColor":"bg-neon-green"},{"id":"1980-31","word":"아더매치","era":"1980년대","meaning":"'아니꼽고 더럽고 매스껍고 치사하다'의 첫 글자를 딴 유행어","example":"그 얘기 듣고 나니 참 아더매치하구먼!","tags":["유행어","해학"],"themeColor":"bg-neon-blue"},{"id":"1980-32","word":"옥떨메","era":"1980년대","meaning":"'옥상에서 떨어진 메주'의 줄임말로, 못생겼다고 놀리던 짓궂은 유행어","example":"친구들끼리 옥떨메라고 놀리다가 진짜 싸움 난 적도 있었지.","tags":["유행어","학창시절"],"themeColor":"bg-neon-pink"},{"id":"1980-33","word":"CC","era":"1980년대","meaning":"'캠퍼스 커플'의 줄임말로, 같은 대학에서 만나 사귀는 연인","example":"우리 과 CC 커플이 결혼까지 골인해서 다들 부러워했어.","tags":["연애","대학"],"themeColor":"bg-neon-orange"},{"id":"1980-34","word":"부킹","era":"1980년대","meaning":"나이트클럽에서 웨이터가 남녀 테이블을 이어주던 만남 주선 문화","example":"친구 따라 나이트 갔다가 부킹으로 지금 집사람을 만났다니까.","tags":["연애","나이트"],"themeColor":"bg-neon-green"},{"id":"1980-35","word":"나이트클럽","era":"1980년대","meaning":"화려한 조명 아래 춤추고 부킹하던 밤 문화의 중심지","example":"월급날이면 동료들이랑 나이트 가서 스트레스를 풀었지.","tags":["유흥","춤"],"themeColor":"bg-neon-blue"},{"id":"1980-36","word":"빽판","era":"1980년대","meaning":"정식 수입되지 않은 팝 음반을 몰래 복제한 해적판 LP","example":"청계천에서 빽판 뒤지며 팝송 명반을 찾아다녔어.","tags":["음악","LP"],"themeColor":"bg-neon-pink"},{"id":"1980-37","word":"경양식집","era":"1980년대","meaning":"돈가스에 크림수프가 나오던 서양식 레스토랑으로, 최고의 데이트 코스였다","example":"경양식집에서 '밥으로 드릴까요 빵으로 드릴까요' 물으면 괜히 긴장했지.","tags":["데이트","외식"],"themeColor":"bg-neon-orange"},{"id":"1980-38","word":"공중전화","era":"1980년대","meaning":"동전 넣고 걸던 길거리 전화로, 퇴근길이면 줄이 길게 늘어섰다","example":"동전 떨어질까 봐 십 원짜리 잔뜩 들고 공중전화 앞에 줄 섰지.","tags":["통신","생활"],"themeColor":"bg-neon-green"},{"id":"1980-39","word":"회수권","era":"1980년대","meaning":"버스 요금을 미리 묶음으로 사던 종이 승차권으로, 학생들의 필수품이었다","example":"회수권 열 장 묶음을 11장으로 잘라 쓰다 걸린 친구도 있었잖아.","tags":["교통","학생"],"themeColor":"bg-neon-blue"},{"id":"1980-40","word":"토큰","era":"1980년대","meaning":"버스 요금 대신 내던 동그란 주화 모양의 승차표","example":"주머니 속 토큰 짤랑거리는 소리가 등굣길 소리였지.","tags":["교통","생활"],"themeColor":"bg-neon-pink"},{"id":"1980-41","word":"쫀드기","era":"1980년대","meaning":"문방구에서 팔던 쫄깃한 불량식품의 왕으로, 연탄불에 구워 먹으면 별미였다","example":"쫀드기 구워 먹다 태워서 문방구 아줌마한테 혼났네.","tags":["간식","문방구"],"themeColor":"bg-neon-orange"},{"id":"1980-42","word":"아폴로","era":"1980년대","meaning":"빨대 모양 비닐에 든 새콤달콤한 가루 과자로, 문방구 앞 인기 간식이었다","example":"아폴로 쪽쪽 빨며 하교하던 그 길이 그립구먼.","tags":["간식","문방구"],"themeColor":"bg-neon-green"},{"id":"1980-43","word":"달고나","era":"1980년대","meaning":"설탕을 녹여 소다를 넣고 부풀린 뽑기 과자로, 모양 뜨기에 성공하면 하나 더 줬다","example":"달고나 별 모양 뜨다가 침 발라가며 조심조심 눌렀는데 결국 부러졌지.","tags":["간식","뽑기"],"themeColor":"bg-neon-blue"},{"id":"1980-44","word":"문방구","era":"1980년대","meaning":"학용품부터 불량식품·조립장난감까지 다 있던 학교 앞 만물상","example":"문방구 앞 오락기 앞에 쭈그리고 앉아 구경만 해도 좋았어.","tags":["가게","학교앞"],"themeColor":"bg-neon-pink"},{"id":"1980-45","word":"아기공룡 둘리","era":"1980년대","meaning":"1983년 탄생한 국민 만화 캐릭터로, '요리보고 조리봐도' 주제가가 유명하다","example":"둘리 만화영화 하는 시간엔 밖에서 놀다가도 뛰어 들어왔지.","tags":["만화","캐릭터"],"themeColor":"bg-neon-orange"},{"id":"1980-46","word":"달려라 하니","era":"1980년대","meaning":"엄마를 그리며 달리는 소녀 하니의 이야기로, 온 국민을 울린 만화영화","example":"하니가 달릴 때마다 나도 모르게 주먹을 꼭 쥐고 응원했어.","tags":["만화","감동"],"themeColor":"bg-neon-green"},{"id":"1980-47","word":"맥가이버","era":"1980년대","meaning":"주머니칼 하나로 뭐든 해결하던 외화 주인공으로, '맥가이버칼'이란 말까지 남겼다","example":"맥가이버 보고 나면 뭐든 고칠 수 있을 것 같은 기분이 들었지.","tags":["외화","방송"],"themeColor":"bg-neon-blue"},{"id":"1980-48","word":"오빠부대","era":"1980년대","meaning":"조용필 팬들에게서 시작된 말로, 가수를 쫓아다니며 열광하던 팬덤의 원조","example":"조용필 공연장은 오빠부대 함성으로 노래가 안 들릴 정도였다니까.","tags":["가요","팬덤"],"themeColor":"bg-neon-pink"},{"id":"1980-49","word":"비둘기호","era":"1980년대","meaning":"역마다 다 서던 가장 느리고 정겨운 완행열차","example":"비둘기호 타고 삶은 달걀 까먹으며 외갓집 가던 길이 소풍 같았지.","tags":["기차","여행"],"themeColor":"bg-neon-orange"},{"id":"1980-50","word":"88서울올림픽","era":"1980년대","meaning":"1988년 서울에서 열린 하계올림픽으로, '손에 손잡고' 노래와 함께 온 나라가 들썩였다","example":"88올림픽 개회식 날은 온 동네 사람들이 한 집에 모여 봤어.","tags":["올림픽","국가행사"],"themeColor":"bg-neon-green"},{"id":"1990-21","word":"서태지 신드롬","era":"1990년대","meaning":"1992년 등장한 서태지와 아이들이 몰고 온 사회 현상으로, '문화대통령'이라 불렸다","example":"난 알아요 나오고 나서 세상 음악이 다 바뀐 것 같았지.","tags":["가요","문화"],"themeColor":"bg-neon-blue"},{"id":"1990-22","word":"8282","era":"1990년대","meaning":"삐삐에 찍어 보내던 숫자 암호로 '빨리빨리'라는 뜻","example":"삐삐에 8282 찍히면 공중전화로 부리나케 달려갔지.","tags":["삐삐","암호"],"themeColor":"bg-neon-pink"},{"id":"1990-23","word":"1004","era":"1990년대","meaning":"삐삐 숫자 암호로 '천사'라는 뜻. 연인들의 애정 표현이었다","example":"퇴근길에 1004 찍어 보내는 게 그 시절 연애편지였어.","tags":["삐삐","연애"],"themeColor":"bg-neon-orange"},{"id":"1990-24","word":"PC통신","era":"1990년대","meaning":"전화선으로 접속하던 인터넷의 조상으로, 파란 화면에 채팅과 동호회가 꽃폈다","example":"PC통신 접속음 삐— 소리만 들어도 가슴이 설렜지.","tags":["통신","컴퓨터"],"themeColor":"bg-neon-green"},{"id":"1990-25","word":"천리안·하이텔","era":"1990년대","meaning":"PC통신 시대 양대 서비스로, 채팅방과 동호회 문화의 발상지","example":"하이텔 영화 동호회에서 만난 사람들이랑 아직도 연락해.","tags":["통신","동호회"],"themeColor":"bg-neon-blue"},{"id":"1990-26","word":"채팅","era":"1990년대","meaning":"PC통신에서 글자로 나누던 대화로, '방가방가' 같은 채팅 용어를 낳았다","example":"밤새 채팅하다 전화요금 고지서 보고 기절할 뻔했잖아.","tags":["통신","대화"],"themeColor":"bg-neon-pink"},{"id":"1990-27","word":"시티폰","era":"1990년대","meaning":"공중전화 근처에서만 걸 수 있던 발신 전용 휴대전화로, 휴대폰의 과도기였다","example":"시티폰 들고 공중전화 부스 옆에서 전화 걸던 모습이 우습지도 않았지.","tags":["통신","휴대폰"],"themeColor":"bg-neon-orange"},{"id":"1990-28","word":"노래방","era":"1990년대","meaning":"1991년 부산에서 시작해 전국을 휩쓴 국민 놀이문화","example":"회식 2차는 무조건 노래방이었지, 십팔번 한 곡씩 뽑고 나야 끝났어.","tags":["놀이","노래"],"themeColor":"bg-neon-green"},{"id":"1990-29","word":"다마고치","era":"1990년대","meaning":"1997년 유행한 손바닥만 한 전자 애완동물 키우기 게임","example":"다마고치 밥 준다고 수업 시간에 몰래 꺼냈다가 뺏겼잖아.","tags":["게임","유행"],"themeColor":"bg-neon-blue"},{"id":"1990-30","word":"금모으기 운동","era":"1990년대","meaning":"IMF 외환위기 때 온 국민이 장롱 속 금붙이를 내놓은 운동","example":"돌반지까지 내놓으면서도 나라 살리자고 다들 한마음이었지.","tags":["시대상","IMF"],"themeColor":"bg-neon-pink"},{"id":"1990-31","word":"Y2K","era":"1990년대","meaning":"2000년이 되면 컴퓨터가 연도를 잘못 읽어 대혼란이 온다던 밀레니엄 버그 소동","example":"Y2K 때문에 12월 31일에 현금 뽑아놓고 라면까지 사뒀다니까.","tags":["시대상","컴퓨터"],"themeColor":"bg-neon-orange"},{"id":"1990-32","word":"밀레니엄","era":"1990년대","meaning":"2000년 새천년을 맞는 설렘과 들뜸을 담았던 시대의 유행어","example":"밀레니엄 첫 해돋이 보겠다고 정동진행 기차표를 겨우 구했지.","tags":["시대상","새천년"],"themeColor":"bg-neon-green"},{"id":"1990-33","word":"노스트라다무스","era":"1990년대","meaning":"1999년 지구가 멸망한다는 예언으로 화제가 됐던 프랑스 예언가","example":"1999년 7월에 다들 진짜 무슨 일 나는 줄 알고 은근히 떨었잖아.","tags":["시대상","화제"],"themeColor":"bg-neon-blue"},{"id":"1990-34","word":"공주병","era":"1990년대","meaning":"자기가 공주인 줄 안다며 놀리던 유행어. 남자는 왕자병이라 불렀다","example":"거울만 보면 공주병이냐고 친구들끼리 놀려댔지.","tags":["유행어","해학"],"themeColor":"bg-neon-pink"},{"id":"1990-35","word":"왕자병","era":"1990년대","meaning":"스스로 왕자님인 줄 아는 남자를 놀리던 말로, 공주병과 짝을 이뤘다","example":"그 친구는 왕자병이 심해서 사진 찍을 때마다 폼을 잡았어.","tags":["유행어","해학"],"themeColor":"bg-neon-orange"},{"id":"1990-36","word":"날라리","era":"1990년대","meaning":"공부보다 노는 데 열심인 학생을 이르던 말","example":"날라리 소리 듣던 짝꿍이 지금은 사업가로 제일 성공했다니까.","tags":["학창시절","유행어"],"themeColor":"bg-neon-green"},{"id":"1990-37","word":"담탱이","era":"1990년대","meaning":"담임선생님을 몰래 부르던 학생들의 은어","example":"담탱이 뜬다! 하면 다들 만화책을 서랍에 숨겼지.","tags":["학교","은어"],"themeColor":"bg-neon-blue"},{"id":"1990-38","word":"길보드 차트","era":"1990년대","meaning":"길거리 리어카에서 팔던 인기가요 테이프 순위를 빌보드에 빗댄 말","example":"길보드 차트 1위 테이프 사서 워크맨이 늘어지게 들었어.","tags":["가요","길거리"],"themeColor":"bg-neon-pink"},{"id":"1990-39","word":"비디오 대여점","era":"1990년대","meaning":"주말이면 온 가족이 비디오테이프를 빌리러 가던 동네 가게","example":"주말의 명화 대신 비디오 빌려서 온 식구가 모여 봤지.","tags":["가게","영화"],"themeColor":"bg-neon-orange"},{"id":"1990-40","word":"만화방","era":"1990년대","meaning":"라면 시켜 먹으며 만화책을 밤새 보던 만화 대여점","example":"만화방에서 라면 국물에 김밥 말아먹으며 무협지 완독했다니까.","tags":["가게","만화"],"themeColor":"bg-neon-green"},{"id":"1990-41","word":"풍선 응원","era":"1990년대","meaning":"1세대 아이돌 팬클럽이 가수마다 정해진 색깔 풍선을 흔들던 응원 문화","example":"조카 따라 공연장 갔더니 객석이 온통 하얀 풍선 물결이더라고.","tags":["가요","팬덤"],"themeColor":"bg-neon-blue"},{"id":"1990-42","word":"롤러블레이드","era":"1990년대","meaning":"1990년대 중반 공원마다 유행한 인라인스케이트","example":"한강공원에서 롤러블레이드 타다가 엉덩방아 찧던 게 어제 같네.","tags":["운동","유행"],"themeColor":"bg-neon-pink"},{"id":"1990-43","word":"힙합바지","era":"1990년대","meaning":"허리는 내리고 통은 넓게 입던 힙합 스타일 배기바지","example":"아들 녀석 힙합바지가 흘러내릴까 봐 내가 다 조마조마했지.","tags":["패션","유행"],"themeColor":"bg-neon-orange"},{"id":"1990-44","word":"배꼽티","era":"1990년대","meaning":"배꼽이 드러나게 짧게 입던 티셔츠로, 세기말 패션의 상징","example":"배꼽티 입고 나간 딸을 보고 기함했던 게 엊그제 같은데 말이야.","tags":["패션","유행"],"themeColor":"bg-neon-green"},{"id":"1990-45","word":"헤어무스","era":"1990년대","meaning":"머리를 세우고 고정하던 거품형 스타일링 제품으로, 멋쟁이의 필수품","example":"무스 잔뜩 발라 앞머리 세우고 나가야 미팅에 자신이 붙었지.","tags":["패션","멋"],"themeColor":"bg-neon-blue"},{"id":"1990-46","word":"486 컴퓨터","era":"1990년대","meaning":"1990년대 초중반 가정용 컴퓨터의 대명사로, 있는 집 아이들의 자랑이었다","example":"486 컴퓨터 들여놓은 날, 온 가족이 돌아가며 자판을 눌러봤어.","tags":["컴퓨터","가전"],"themeColor":"bg-neon-pink"},{"id":"1990-47","word":"PC방","era":"1990년대","meaning":"1998년 스타크래프트 열풍과 함께 골목마다 생겨난 게임 공간","example":"아들 찾으러 PC방 순례하던 게 그 시절 엄마들 일과였지.","tags":["게임","가게"],"themeColor":"bg-neon-orange"},{"id":"1990-48","word":"스타크래프트","era":"1990년대","meaning":"1998년 출시돼 PC방 열풍을 일으킨 국민 전략 게임","example":"조카들이 스타 한 판만 더 하고 잔다는 말을 믿으면 안 됐어.","tags":["게임","유행"],"themeColor":"bg-neon-green"},{"id":"1990-49","word":"이스트팩","era":"1990년대","meaning":"1990년대 중고생 사이에서 유행한 책가방 브랜드로, 한쪽 어깨로 메는 게 멋이었다","example":"이스트팩 사달라고 조르던 아이 성화에 못 이겨 백화점에 갔지.","tags":["패션","학생"],"themeColor":"bg-neon-blue"},{"id":"1990-50","word":"공중전화카드","era":"1990년대","meaning":"동전 대신 쓰던 마그네틱 전화카드로, 그림이 예뻐 수집 붐까지 일었다","example":"쓰고 난 전화카드를 앨범에 모으는 게 소소한 재미였어.","tags":["통신","수집"],"themeColor":"bg-neon-pink"},{"id":"2000-21","word":"싸이월드","era":"2000년대","meaning":"2000년대를 풍미한 국민 SNS로, 미니홈피·도토리·일촌 문화를 낳았다","example":"싸이월드 배경음악 고르느라 도토리를 얼마나 썼는지 몰라.","tags":["SNS","인터넷"],"themeColor":"bg-neon-orange"},{"id":"2000-22","word":"미니홈피","era":"2000년대","meaning":"싸이월드의 개인 홈페이지로, 미니룸 꾸미기와 방명록이 핵심이었다","example":"미니홈피 스킨 바꾸고 친구들 방명록 돌던 시절이 있었지.","tags":["SNS","인터넷"],"themeColor":"bg-neon-green"},{"id":"2000-23","word":"도토리","era":"2000년대","meaning":"싸이월드에서 배경음악·스킨을 사던 사이버 화폐","example":"조카 생일선물로 도토리 10개 쏘면 최고 삼촌 소리 들었어.","tags":["SNS","화폐"],"themeColor":"bg-neon-blue"},{"id":"2000-24","word":"일촌","era":"2000년대","meaning":"싸이월드에서 맺던 친구 관계로, '일촌명'을 정하는 재미가 있었다","example":"일촌명 뭐라고 지을지 고민하다 밤을 새웠다니까.","tags":["SNS","친구"],"themeColor":"bg-neon-pink"},{"id":"2000-25","word":"파도타기","era":"2000년대","meaning":"일촌의 일촌으로 미니홈피를 타고 타고 구경 다니던 것","example":"파도타기 하다 보면 어느새 모르는 사람 홈피에 가 있었지.","tags":["SNS","인터넷"],"themeColor":"bg-neon-orange"},{"id":"2000-26","word":"퍼가요~♡","era":"2000년대","meaning":"싸이월드에서 남의 글·사진을 스크랩할 때 남기던 인사말","example":"좋은 글 밑엔 어김없이 퍼가요~♡ 댓글이 줄줄이 달렸어.","tags":["SNS","유행어"],"themeColor":"bg-neon-green"},{"id":"2000-27","word":"버디버디","era":"2000년대","meaning":"2000년대 초 학생들이 쓰던 국민 메신저","example":"버디버디 아이디 주고받는 게 그 시절 전화번호 교환이었지.","tags":["메신저","인터넷"],"themeColor":"bg-neon-blue"},{"id":"2000-28","word":"컬러링","era":"2000년대","meaning":"전화 걸 때 상대에게 들려주던 통화연결음으로, 최신곡 컬러링이 유행이었다","example":"컬러링 듣고 그 사람 취향을 짐작하곤 했잖아.","tags":["휴대폰","음악"],"themeColor":"bg-neon-pink"},{"id":"2000-29","word":"벨소리 다운","era":"2000년대","meaning":"휴대폰 벨소리를 유료로 내려받던 문화로, 16화음·64화음을 따졌다","example":"64화음 벨소리 자랑하려고 일부러 전화 올 때까지 기다렸지.","tags":["휴대폰","음악"],"themeColor":"bg-neon-orange"},{"id":"2000-30","word":"MP3 플레이어","era":"2000년대","meaning":"CD 없이 음악을 담아 듣던 기기로, 아이리버가 국민 브랜드였다","example":"MP3에 노래 100곡 담아 다니는 게 그렇게 신기했어.","tags":["기기","음악"],"themeColor":"bg-neon-green"},{"id":"2000-31","word":"디카","era":"2000년대","meaning":"'디지털카메라'의 줄임말로, 필름 걱정 없이 마음껏 찍는 시대를 열었다","example":"디카 사고 나서 사진관 갈 일이 뚝 끊겼지.","tags":["기기","사진"],"themeColor":"bg-neon-blue"},{"id":"2000-32","word":"폰카","era":"2000년대","meaning":"'폰 카메라'의 줄임말로, 휴대폰으로 사진 찍는 문화의 시작","example":"폰카 화소가 낮아도 그 흐릿한 사진이 지금 보면 더 정겨워.","tags":["휴대폰","사진"],"themeColor":"bg-neon-pink"},{"id":"2000-33","word":"셀카","era":"2000년대","meaning":"'셀프 카메라'의 줄임말로, 자기 모습을 스스로 찍는 것","example":"손 뻗어 셀카 찍는 게 처음엔 그렇게 어색했다니까.","tags":["사진","유행"],"themeColor":"bg-neon-orange"},{"id":"2000-34","word":"얼짱각도","era":"2000년대","meaning":"45도 위에서 내려 찍으면 예뻐 보인다던 셀카의 정석 각도","example":"얼짱각도로 찍어야 미니홈피 대문사진감이 나왔지.","tags":["사진","유행"],"themeColor":"bg-neon-green"},{"id":"2000-35","word":"하두리","era":"2000년대","meaning":"웹캠으로 셀카를 찍던 서비스로, '하두리 얼짱'이라는 말을 낳았다","example":"하두리 캠으로 찍은 뽀샤시 사진이 대문마다 걸려 있었어.","tags":["사진","인터넷"],"themeColor":"bg-neon-blue"},{"id":"2000-36","word":"쌩얼","era":"2000년대","meaning":"화장하지 않은 맨 얼굴을 이르는 말","example":"쌩얼로 나왔다가 아는 사람 만나서 혼비백산했지 뭐야.","tags":["유행어","일상"],"themeColor":"bg-neon-pink"},{"id":"2000-37","word":"짤방","era":"2000년대","meaning":"'짤림 방지'의 줄임말로, 글이 삭제되지 않게 올리던 사진에서 유래해 재미난 이미지를 뜻하게 됐다","example":"요즘 애들이 보내는 웃긴 그림을 짤이라고 부르더라고.","tags":["인터넷","유행어"],"themeColor":"bg-neon-orange"},{"id":"2000-38","word":"리플","era":"2000년대","meaning":"'리플라이(reply)'의 줄임말로, 댓글의 원조 표현","example":"기사에 리플 단다고 하면 요즘 애들은 못 알아듣더라니까.","tags":["인터넷","유행어"],"themeColor":"bg-neon-green"},{"id":"2000-39","word":"아햏햏","era":"2000년대","meaning":"2002년경 인터넷을 휩쓴 정체불명의 감탄사로, 묘한 것을 봤을 때 썼다","example":"그 시절 게시판마다 아햏햏 소리가 도배됐었지.","tags":["인터넷","유행어"],"themeColor":"bg-neon-blue"},{"id":"2000-40","word":"므흣","era":"2000년대","meaning":"흐뭇하면서 알쏭달쏭한 미소를 표현하던 인터넷 유행어","example":"손주 재롱 영상 보니 나도 모르게 므흣한 웃음이 나네.","tags":["인터넷","유행어"],"themeColor":"bg-neon-pink"},{"id":"2000-41","word":"흠좀무","era":"2000년대","meaning":"'흠 좀 무섭네요'의 줄임말로, 놀라운 이야기에 달던 반응","example":"그 소문이 사실이라니, 흠좀무구먼.","tags":["인터넷","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2000-42","word":"열폭","era":"2000년대","meaning":"'열등감 폭발'의 줄임말로, 샘이 나서 발끈하는 모습","example":"동창 자랑에 열폭하지 말고 우리는 우리 인생 살자고.","tags":["유행어","줄임말"],"themeColor":"bg-neon-green"},{"id":"2000-43","word":"문상","era":"2000년대","meaning":"'문화상품권'의 줄임말로, 학생들의 만능 선물이자 용돈이었다","example":"조카 용돈 대신 문상 주면 그렇게 좋아했어.","tags":["줄임말","선물"],"themeColor":"bg-neon-blue"},{"id":"2000-44","word":"리니지","era":"2000년대","meaning":"2000년대를 대표하는 국민 온라인 게임으로, 아이템 열풍을 일으켰다","example":"옆집 총각이 리니지 아이템 팔아 용돈 벌었다는 얘기에 다들 놀랐지.","tags":["게임","인터넷"],"themeColor":"bg-neon-pink"},{"id":"2000-45","word":"카트라이더","era":"2000년대","meaning":"온 가족이 함께 즐긴 국민 카트 레이싱 게임","example":"손주랑 카트라이더 한 판 했다가 어지러워서 혼났네.","tags":["게임","가족"],"themeColor":"bg-neon-orange"},{"id":"2000-46","word":"웰빙","era":"2000년대","meaning":"몸과 마음의 건강을 챙기자는 2000년대 중반의 생활 열풍","example":"웰빙 바람 불면서 우리 집 밥상에도 현미밥이 올라왔지.","tags":["건강","유행"],"themeColor":"bg-neon-green"},{"id":"2000-47","word":"몸짱","era":"2000년대","meaning":"'몸이 짱'이라는 뜻으로, 2003년 몸짱 아줌마 신드롬과 함께 운동 열풍을 일으켰다","example":"몸짱 열풍에 나도 새벽 헬스장을 끊었었잖아.","tags":["건강","유행"],"themeColor":"bg-neon-blue"},{"id":"2000-48","word":"베프","era":"2000년대","meaning":"'베스트 프렌드'의 줄임말로, 가장 친한 친구","example":"50년 지기 내 베프는 지금도 매주 목욕탕을 같이 가.","tags":["줄임말","우정"],"themeColor":"bg-neon-pink"},{"id":"2000-49","word":"광클","era":"2000년대","meaning":"'미친 듯이 클릭한다'는 뜻으로, 티켓 예매 경쟁에서 나온 말","example":"공연표 구한다고 온 식구가 광클했는데 결국 실패했어.","tags":["인터넷","유행어"],"themeColor":"bg-neon-orange"},{"id":"2000-50","word":"눈팅","era":"2000년대","meaning":"글은 안 쓰고 눈으로 보기만 한다는 뜻의 인터넷 용어","example":"동창회 단체방은 눈팅만 하는데 다 읽고는 있어.","tags":["인터넷","유행어"],"themeColor":"bg-neon-green"},{"id":"2010-21","word":"썸","era":"2010년대","meaning":"사귀기 전 서로 마음을 살피는 미묘한 단계. '썸 탄다'고 말한다","example":"요즘 우리 손녀가 썸 탄다는데 얼굴이 아주 폈어.","tags":["연애","유행어"],"themeColor":"bg-neon-blue"},{"id":"2010-22","word":"밀당","era":"2010년대","meaning":"'밀고 당기기'의 줄임말로, 연애에서 관심을 줬다 뺐다 하는 심리전","example":"우리 때는 밀당이란 말은 없어도 다들 은근히 하고 있었지.","tags":["연애","줄임말"],"themeColor":"bg-neon-pink"},{"id":"2010-23","word":"멘붕","era":"2010년대","meaning":"'멘탈 붕괴'의 줄임말로, 정신이 아득해질 만큼 충격받은 상태","example":"비밀번호를 몽땅 잊어버려서 아주 멘붕이 왔었다니까.","tags":["유행어","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2010-24","word":"먹방","era":"2010년대","meaning":"'먹는 방송'의 줄임말로, 음식 먹는 모습을 보여주는 방송","example":"밤에 먹방 보다가 참지 못하고 라면 끓인 게 한두 번이 아니야.","tags":["방송","음식"],"themeColor":"bg-neon-green"},{"id":"2010-25","word":"쿡방","era":"2010년대","meaning":"'요리(cook) 방송'의 줄임말로, 요리 과정을 보여주는 방송","example":"쿡방 보고 따라 했더니 우리 영감이 웬일로 맛있다고 하네.","tags":["방송","요리"],"themeColor":"bg-neon-blue"},{"id":"2010-26","word":"혼밥","era":"2010년대","meaning":"'혼자 먹는 밥'의 줄임말로, 혼자 식사하는 문화","example":"처음엔 혼밥이 쓸쓸했는데 이젠 편해서 좋더라고.","tags":["일상","줄임말"],"themeColor":"bg-neon-pink"},{"id":"2010-27","word":"혼술","era":"2010년대","meaning":"'혼자 마시는 술'의 줄임말로, 혼자만의 여유를 즐기는 음주 문화","example":"드라마 보면서 혼술 한잔하는 게 요즘 낙이야.","tags":["일상","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2010-28","word":"욜로","era":"2010년대","meaning":"'인생은 한 번뿐(You Only Live Once)'의 약자로, 현재를 즐기자는 생활 태도","example":"욜로라고 아들이 덜컥 여행부터 끊더니, 뭐 보기는 좋더라.","tags":["유행어","생활"],"themeColor":"bg-neon-green"},{"id":"2010-29","word":"가성비","era":"2010년대","meaning":"'가격 대비 성능의 비율'로, 싸고 좋은 물건을 고르는 기준","example":"이 국밥집이 가성비가 최고야, 팔천 원에 이 양이면.","tags":["소비","줄임말"],"themeColor":"bg-neon-blue"},{"id":"2010-30","word":"가심비","era":"2010년대","meaning":"가격 대비 마음(心)의 만족을 따지는 소비 기준","example":"비싸도 기분 좋아지면 그게 가심비 아니겠어.","tags":["소비","유행어"],"themeColor":"bg-neon-pink"},{"id":"2010-31","word":"갬성","era":"2010년대","meaning":"'감성'을 멋스럽게 발음한 말로, 분위기 있는 것들을 이른다","example":"손녀가 찍어준 카페 사진이 아주 갬성 넘친다고 하더라고.","tags":["유행어","감성"],"themeColor":"bg-neon-orange"},{"id":"2010-32","word":"인생샷","era":"2010년대","meaning":"인생에서 가장 잘 나온 사진이라는 뜻","example":"제주도 유채꽃밭에서 인생샷 하나 건졌지.","tags":["사진","유행어"],"themeColor":"bg-neon-green"},{"id":"2010-33","word":"인생템","era":"2010년대","meaning":"인생 최고의 물건(아이템)이라는 뜻","example":"이 안마기가 내 인생템이야, 하루도 못 빼먹어.","tags":["소비","유행어"],"themeColor":"bg-neon-blue"},{"id":"2010-34","word":"웃프다","era":"2010년대","meaning":"웃긴데 슬프다는 뜻으로, 두 감정이 뒤섞일 때 쓴다","example":"늙어가는 얘기로 친구들과 한참 웃었는데 돌아서니 웃프더라고.","tags":["유행어","감정"],"themeColor":"bg-neon-pink"},{"id":"2010-35","word":"답정너","era":"2010년대","meaning":"'답은 정해져 있고 너는 대답만 하면 돼'의 줄임말","example":"새 옷 어떠냐고 물을 땐 사실 답정너인 거 알지?","tags":["유행어","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2010-36","word":"읽씹","era":"2010년대","meaning":"메시지를 읽고도 답하지 않는 것. '읽고 씹는다'의 줄임말","example":"아들한테 읽씹 당하면 그렇게 서운할 수가 없어.","tags":["메신저","줄임말"],"themeColor":"bg-neon-green"},{"id":"2010-37","word":"단톡방","era":"2010년대","meaning":"'단체 카카오톡 방'의 줄임말로, 여럿이 함께 대화하는 채팅방","example":"동창 단톡방 알림이 하루에 백 개는 울려.","tags":["메신저","줄임말"],"themeColor":"bg-neon-blue"},{"id":"2010-38","word":"프사","era":"2010년대","meaning":"'프로필 사진'의 줄임말로, 메신저에 걸어두는 대표 사진","example":"손주 사진으로 프사 바꿨더니 다들 예쁘다고 난리야.","tags":["메신저","줄임말"],"themeColor":"bg-neon-pink"},{"id":"2010-39","word":"셀기꾼","era":"2010년대","meaning":"'셀카+사기꾼'의 합성어로, 실물보다 사진이 잘 나오는 사람","example":"사진이랑 너무 다르면 셀기꾼 소리 듣는다더라고.","tags":["사진","해학"],"themeColor":"bg-neon-orange"},{"id":"2010-40","word":"금사빠","era":"2010년대","meaning":"'금방 사랑에 빠지는 사람'의 줄임말","example":"우리 막내가 금사빠라 걱정이 이만저만이 아니야.","tags":["연애","줄임말"],"themeColor":"bg-neon-green"},{"id":"2010-41","word":"삼귀다","era":"2010년대","meaning":"사귀기 직전 단계라는 뜻의 재치 있는 신조어. '사'귀기 전이니 '삼'귀는 중","example":"요즘 젊은이들은 사귀기 전에 삼귀는 단계가 있다더구먼.","tags":["연애","해학"],"themeColor":"bg-neon-blue"},{"id":"2010-42","word":"그린라이트","era":"2010년대","meaning":"상대가 나에게 호감이 있다는 긍정의 신호","example":"자꾸 반찬을 챙겨주는 걸 보니 그건 그린라이트야.","tags":["연애","유행어"],"themeColor":"bg-neon-pink"},{"id":"2010-43","word":"현웃","era":"2010년대","meaning":"'현실 웃음'의 줄임말로, 화면을 보다 실제로 소리 내어 웃는 것","example":"손주가 보낸 영상 보고 버스에서 현웃 터져서 민망했네.","tags":["유행어","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2010-44","word":"꿀팁","era":"2010년대","meaning":"꿀처럼 달콤하고 유용한 조언이나 요령","example":"파스 냄새 없애는 꿀팁 하나 알려줄까?","tags":["유행어","생활"],"themeColor":"bg-neon-green"},{"id":"2010-45","word":"케바케","era":"2010년대","meaning":"'케이스 바이 케이스'의 줄임말로, 경우에 따라 다르다는 뜻","example":"무릎 수술 결과는 케바케라 하니 미리 걱정 말자고.","tags":["줄임말","유행어"],"themeColor":"bg-neon-blue"},{"id":"2010-46","word":"만렙","era":"2010년대","meaning":"게임의 최고 레벨에서 온 말로, 어떤 분야의 최고 경지를 뜻한다","example":"우리 집사람 김치 담그기는 만렙이지, 50년 경력인데.","tags":["게임","유행어"],"themeColor":"bg-neon-pink"},{"id":"2010-47","word":"순삭","era":"2010년대","meaning":"'순간 삭제'의 줄임말로, 눈 깜짝할 새 사라진다는 뜻","example":"손주들 오면 갈비찜 한 솥이 순삭이야.","tags":["줄임말","해학"],"themeColor":"bg-neon-orange"},{"id":"2010-48","word":"광탈","era":"2010년대","meaning":"'빛의 속도로 탈락'의 줄임말","example":"노래자랑 예선에서 광탈했지만 재미는 있었어.","tags":["줄임말","해학"],"themeColor":"bg-neon-green"},{"id":"2010-49","word":"힐링","era":"2010년대","meaning":"몸과 마음의 상처를 치유한다는 뜻으로, 2010년대 최대 유행어 중 하나","example":"흙 만지고 텃밭 가꾸는 게 나한텐 최고의 힐링이야.","tags":["유행어","생활"],"themeColor":"bg-neon-blue"},{"id":"2010-50","word":"버킷리스트","era":"2010년대","meaning":"죽기 전에 꼭 해보고 싶은 일들의 목록","example":"내 버킷리스트 1번은 자서전 완성하는 거라네.","tags":["유행어","인생"],"themeColor":"bg-neon-pink"},{"id":"2020-21","word":"라떼는 말이야","era":"2020년대","meaning":"'나 때는 말이야'를 재치 있게 비튼 말로, 옛날 얘기를 꺼내는 어른을 놀리는 표현","example":"손주한테 옛날 얘기 시작하면 '할아버지 라떼는 말이야~' 하고 웃더라고.","tags":["유행어","해학"],"themeColor":"bg-neon-orange"},{"id":"2020-22","word":"얼죽아","era":"2020년대","meaning":"'얼어 죽어도 아이스 아메리카노'의 줄임말로, 한겨울에도 찬 커피만 마시는 사람","example":"우리 딸이 얼죽아라 한겨울에도 얼음 커피를 들고 다녀.","tags":["줄임말","커피"],"themeColor":"bg-neon-green"},{"id":"2020-23","word":"아아","era":"2020년대","meaning":"'아이스 아메리카노'의 줄임말. 뜨거운 것은 '뜨아'라고 한다","example":"카페 가서 아아 한 잔이요 했더니 손녀가 깜짝 놀라더라고.","tags":["줄임말","커피"],"themeColor":"bg-neon-blue"},{"id":"2020-24","word":"댕댕이","era":"2020년대","meaning":"'멍멍이'와 글자 모양이 비슷해서 생긴 말로, 강아지를 귀엽게 부르는 표현","example":"공원에 나가면 댕댕이 구경하는 재미로 걷지.","tags":["유행어","반려동물"],"themeColor":"bg-neon-pink"},{"id":"2020-25","word":"할매니얼","era":"2020년대","meaning":"'할머니+밀레니얼'의 합성어로, 약과·흑임자 같은 옛날 입맛을 즐기는 젊은 세대","example":"요즘 젊은이들이 할매니얼이라고 약과에 줄을 선다니 세상 참.","tags":["유행","세대"],"themeColor":"bg-neon-orange"},{"id":"2020-26","word":"뉴트로","era":"2020년대","meaning":"'뉴(new)+레트로'의 합성어로, 옛것을 요즘 감각으로 즐기는 유행","example":"우리 때 다방커피가 뉴트로라고 다시 인기라네.","tags":["유행","복고"],"themeColor":"bg-neon-green"},{"id":"2020-27","word":"어른이","era":"2020년대","meaning":"'어른+어린이'의 합성어로, 동심을 간직한 어른","example":"장난감 모으는 우리 아들은 마흔 넘은 어른이야.","tags":["유행어","합성어"],"themeColor":"bg-neon-blue"},{"id":"2020-28","word":"차박","era":"2020년대","meaning":"'차에서 숙박'의 줄임말로, 차에서 자며 여행하는 캠핑 문화","example":"사위가 차박 간다고 차 뒤를 침대로 꾸몄더라고.","tags":["여행","캠핑"],"themeColor":"bg-neon-pink"},{"id":"2020-29","word":"홈카페","era":"2020년대","meaning":"집을 카페처럼 꾸며 커피와 디저트를 즐기는 문화","example":"딸이 홈카페 차렸다고 커피 내려주는데 다방보다 낫더라.","tags":["집","커피"],"themeColor":"bg-neon-orange"},{"id":"2020-30","word":"홈트","era":"2020년대","meaning":"'홈 트레이닝'의 줄임말로, 집에서 영상 보며 하는 운동","example":"요즘 나도 영상 틀어놓고 홈트로 스트레칭을 해.","tags":["운동","줄임말"],"themeColor":"bg-neon-green"},{"id":"2020-31","word":"플렉스","era":"2020년대","meaning":"'과시하다(flex)'에서 온 말로, 돈을 쓰며 한턱 내거나 자랑하는 것","example":"연금 나온 날 손주들 용돈으로 플렉스 한번 했지.","tags":["소비","유행어"],"themeColor":"bg-neon-blue"},{"id":"2020-32","word":"티키타카","era":"2020년대","meaning":"탁구공이 오가듯 대화가 쉴 새 없이 재미있게 오가는 것","example":"우리 부부는 50년을 살아서 그런지 티키타카가 잘 맞아.","tags":["대화","유행어"],"themeColor":"bg-neon-pink"},{"id":"2020-33","word":"킹받다","era":"2020년대","meaning":"'열받다'에 왕(king)을 붙여 강조한 말로, 몹시 약 오른다는 뜻","example":"바둑에서 지고 나면 킹받는다고 하는 게 요즘 말이라며?","tags":["유행어","감정"],"themeColor":"bg-neon-orange"},{"id":"2020-34","word":"찐","era":"2020년대","meaning":"'진짜'의 줄임말로, 진품·진심을 강조할 때 쓴다","example":"이 집이 평양냉면 찐 맛집이라고 아들이 데려갔어.","tags":["유행어","줄임말"],"themeColor":"bg-neon-green"},{"id":"2020-35","word":"찐텐","era":"2020년대","meaning":"'진짜 텐션'의 줄임말로, 꾸미지 않은 진심 어린 신남","example":"트로트 공연장 가면 나도 모르게 찐텐이 나와.","tags":["유행어","감정"],"themeColor":"bg-neon-blue"},{"id":"2020-36","word":"억텐","era":"2020년대","meaning":"'억지 텐션'의 줄임말로, 즐거운 척 억지로 끌어올린 기분","example":"재미없는데 억텐으로 웃어주는 것도 힘들더라고.","tags":["유행어","감정"],"themeColor":"bg-neon-pink"},{"id":"2020-37","word":"꾸안꾸","era":"2020년대","meaning":"'꾸민 듯 안 꾸민 듯'의 줄임말로, 자연스러운 멋내기","example":"저 배우 옷차림이 딱 꾸안꾸라고 하더구먼.","tags":["패션","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2020-38","word":"손민수","era":"2020년대","meaning":"만화 주인공 이름에서 유래한 말로, 다른 사람의 옷·물건을 그대로 따라 사는 것","example":"손녀가 연예인 가방을 손민수했다고 자랑하더라고.","tags":["소비","유행어"],"themeColor":"bg-neon-green"},{"id":"2020-39","word":"캘박","era":"2020년대","meaning":"'캘린더에 박제'의 줄임말로, 약속을 달력에 확정해 두는 것","example":"다음 달 동창회 날짜 캘박해 두라고 아들한테 부탁했지.","tags":["줄임말","약속"],"themeColor":"bg-neon-blue"},{"id":"2020-40","word":"만반잘부","era":"2020년대","meaning":"'만나서 반가워 잘 부탁해'의 줄임말","example":"새로 온 경로당 회원한테 만반잘부라고 했더니 다들 웃어.","tags":["줄임말","인사"],"themeColor":"bg-neon-pink"},{"id":"2020-41","word":"좋댓구알","era":"2020년대","meaning":"'좋아요·댓글·구독·알림설정'의 줄임말로, 유튜버들의 인사말","example":"우리 손주 유튜브 한다고 좋댓구알 눌러달라네.","tags":["유튜브","줄임말"],"themeColor":"bg-neon-orange"},{"id":"2020-42","word":"완내스","era":"2020년대","meaning":"'완전 내 스타일'의 줄임말","example":"이 꽃무늬 블라우스 완내스야, 하나 사야겠어.","tags":["줄임말","취향"],"themeColor":"bg-neon-green"},{"id":"2020-43","word":"하울","era":"2020년대","meaning":"산 물건을 잔뜩 펼쳐놓고 보여주는 영상 콘텐츠","example":"딸이 시장 하울 영상을 찍는다고 장바구니를 다 펼치더라.","tags":["유튜브","소비"],"themeColor":"bg-neon-blue"},{"id":"2020-44","word":"인스타각","era":"2020년대","meaning":"인스타그램에 올릴 만큼 근사하다는 뜻","example":"음식이 나오자마자 손녀가 인스타각이라며 사진부터 찍어.","tags":["SNS","사진"],"themeColor":"bg-neon-pink"},{"id":"2020-45","word":"N잡러","era":"2020년대","meaning":"직업을 여러 개(N개) 가진 사람","example":"요즘 젊은 사람들은 낮엔 회사, 밤엔 장사하는 N잡러가 많다네.","tags":["직업","세대"],"themeColor":"bg-neon-orange"},{"id":"2020-46","word":"힙하다","era":"2020년대","meaning":"개성 있고 세련되게 멋지다는 뜻","example":"손주 말로는 요즘 우리 재래시장이 힙한 곳이 됐다더라고.","tags":["유행어","멋"],"themeColor":"bg-neon-green"},{"id":"2020-47","word":"팝업스토어","era":"2020년대","meaning":"짧은 기간만 문을 여는 임시 매장으로, 젊은이들이 줄 서서 찾는다","example":"백화점 팝업스토어에 두 시간을 줄 선다니 대단해.","tags":["소비","유행"],"themeColor":"bg-neon-blue"},{"id":"2020-48","word":"도파민 터진다","era":"2020년대","meaning":"쾌감 호르몬 도파민이 솟는다는 뜻으로, 몹시 재미있고 짜릿할 때 쓴다","example":"트로트 경연 결승은 아주 도파민이 터지더구먼.","tags":["유행어","재미"],"themeColor":"bg-neon-pink"},{"id":"2020-49","word":"맑눈광","era":"2020년대","meaning":"'맑은 눈의 광인'의 줄임말로, 해맑은 얼굴로 엉뚱한 일을 벌이는 사람","example":"우리 막내 손주가 딱 맑눈광이야, 웃는 얼굴로 사고를 쳐.","tags":["줄임말","해학"],"themeColor":"bg-neon-orange"},{"id":"2020-50","word":"별다줄","era":"2020년대","meaning":"'별걸 다 줄인다'의 줄임말로, 줄임말 유행 자체를 꼬집는 말","example":"요즘 말은 별다줄이라 사전이 있어야 알아듣겠어.","tags":["줄임말","해학"],"themeColor":"bg-neon-green"}];
